DROP TABLE IF EXISTS "library_categories";
CREATE TABLE library_categories (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        name TEXT NOT NULL,
        icon TEXT,
        order_index INTEGER NOT NULL DEFAULT 0
    );

DROP TABLE IF EXISTS "library_documents";
CREATE TABLE library_documents (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        category_id INTEGER REFERENCES library_categories(id),
        title TEXT NOT NULL,
        description TEXT,
        filename TEXT NOT NULL,
        original_name TEXT NOT NULL,
        mime_type TEXT,
        size INTEGER,
        uploaded_by INTEGER REFERENCES users(id),
        downloads INTEGER NOT NULL DEFAULT 0,
        created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
    );

DROP TABLE IF EXISTS "maps";
CREATE TABLE maps (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        match_id INTEGER NOT NULL REFERENCES matches(id) ON DELETE CASCADE,
        map_name TEXT NOT NULL,
        winner INTEGER REFERENCES teams(id),
        score TEXT
    );

DROP TABLE IF EXISTS "matches";
CREATE TABLE matches (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        round_id INTEGER NOT NULL REFERENCES rounds(id) ON DELETE CASCADE,
        team1 INTEGER REFERENCES teams(id),
        team2 INTEGER REFERENCES teams(id),
        winner INTEGER REFERENCES teams(id),
        score1 INTEGER,
        score2 INTEGER,
        judge_id INTEGER REFERENCES users(id),
        status TEXT NOT NULL DEFAULT 'scheduled',
        scheduled_at TEXT
    );

INSERT INTO "matches" ("id", "round_id", "team1", "team2", "winner", "score1", "score2", "judge_id", "status", "scheduled_at") VALUES (1, 1, 1, 2, 1, 0, 0, NULL, 'completed', NULL);

DROP TABLE IF EXISTS "meme_comments";
CREATE TABLE meme_comments (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        meme_id INTEGER NOT NULL REFERENCES memes(id) ON DELETE CASCADE,
        user_id INTEGER NOT NULL REFERENCES users(id),
        content TEXT NOT NULL,
        created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
    );

DROP TABLE IF EXISTS "meme_likes";
CREATE TABLE meme_likes (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        meme_id INTEGER NOT NULL REFERENCES memes(id) ON DELETE CASCADE,
        user_id INTEGER NOT NULL REFERENCES users(id)
    );

DROP TABLE IF EXISTS "memes";
CREATE TABLE memes (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        title TEXT,
        image TEXT NOT NULL,
        category TEXT NOT NULL DEFAULT 'general',
        author_id INTEGER REFERENCES users(id),
        likes INTEGER NOT NULL DEFAULT 0,
        created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
    );

DROP TABLE IF EXISTS "messages";
CREATE TABLE messages (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        conversation_id INTEGER NOT NULL REFERENCES conversations(id) ON DELETE CASCADE,
        sender_id INTEGER NOT NULL REFERENCES users(id),
        content TEXT,
        attachment_path TEXT,
        attachment_name TEXT,
        created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
    );

INSERT INTO "messages" ("id", "conversation_id", "sender_id", "content", "attachment_path", "attachment_name", "created_at") VALUES (1, 1, 1, 'дарова это я но не пригожин', NULL, NULL, 'CURRENT_TIMESTAMP');
