DROP TABLE IF EXISTS "movie_comments";
CREATE TABLE movie_comments (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        movie_id INTEGER NOT NULL REFERENCES movies(id) ON DELETE CASCADE,
        user_id INTEGER NOT NULL REFERENCES users(id),
        content TEXT NOT NULL,
        rating INTEGER,
        created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
    );

DROP TABLE IF EXISTS "movies";
CREATE TABLE movies (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        title TEXT NOT NULL,
        year INTEGER,
        genre TEXT NOT NULL DEFAULT 'Боевик',
        rating INTEGER,
        description TEXT,
        poster TEXT,
        added_by INTEGER REFERENCES users(id),
        created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
    );

INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (1, 'Тренер Картер', 2005, 'Драма', 5, 'Фильм основан на реальной истории, происшедшей в 1999 году в Ричмонде, штат Калифорния. Тренер школьной команды по баскетболу Кен Картер принял в середине сезона беспрецедентное решение, запретив игрокам, не испытавшим еще ни одного поражения, выходить на площадку из-за низкой успеваемости в школе. В итоге команда пропустила две игры в чемпионате, а юным баскетболистам был закрыт доступ в спортзал до тех пор, пока они не стали хорошо учиться. Поступок Картера вызвал одновременно и одобрение, и резкую критику со стороны родителей игроков и школьного руководства. Среди членов команды был и сын тренера, поступивший впоследствии в престижное учебное заведение.', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQvNJT4PwhyUjpAKG30Z4dUC7A_PtsgtYHR28bXQQJd2g&s=10', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (2, 'Движение вверх', 2018, 'Драма', 5, 'Есть победы, которые меняют ход истории. Победы духа, победы страны, победы всего мира. Таким триумфом стали легендарные «три секунды» — выигрыш сборной СССР по баскетболу на роковой мюнхенской Олимпиаде 1972 года. Впервые за 36 лет была повержена «непобедимая» команда США. Никто даже помыслить не мог о том, что это возможно — обыграть великолепных непогрешимых американцев на Олимпийских играх!', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSGF0yqAuEHEIUUwH7F7aq0nEmkMGoOCnhi1JpvFihoUw&s=10', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (3, 'Белые не умеют прыгать', 1992, 'Комедия', 4, 'Действие фильма переносит нас на раскаленный асфальт баскетбольных площадок Лос-Анджелеса. Идет игра — игра на деньги. А там где деньги всегда найдется место парочке жуликов, готовых обмануть доверчивого лоха.  Билли, шулер от баскетбола, беззастенчиво пользуется общепринятым мнением, что белый не может играть в баскетбол, не может прыгать. Все складывается отлично, до тех пор пока не приходит время расплачиваться с долгами, наделанными еще в университете. Нужно срочно собрать кругленькую сумму, а в одиночку это проблематично.  К этой проблеме присоединяется еще одна, Сидней — чернокожий мошенник. Звезда уличного баскетбола. Похититель женских сердец.  Между двумя игроками завязывается нешуточная борьба за звание лучшего баскетболиста, ловеласа, самого удачливого кидалы. Борьба идет до тех пор, пока они не понимают, что в паре можно заработать гораздо больше денег, чем по одиночке.', 'https://avatars.mds.yandex.net/get-kinopoisk-image/1773646/6b762599-c48c-4d6f-9e4f-88766617fd4d/576x', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (4, 'Бэтмен: Начало', 2005, 'Боевик', 5, 'В детстве юный наследник огромного состояния Брюс Уэйн оказался свидетелем убийства своих родителей, и тогда он решил бороться с преступностью. Спустя годы он отправляется в путешествие по миру, чтобы найти способ восстановить справедливость. Обучение у мудрого наставника боевым искусствам дает ему силу и смелость. Вернувшись в родной город, Уэйн становится Бэтменом и ведет борьбу со злом.', 'https://avatars.mds.yandex.net/get-ott/18701600/2a0000019c761822f764a13b14f43d5cd5c3/600x900', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (5, 'Тёмный рыцарь', 2008, 'Боевик', 5, 'Бэтмен поднимает ставки в войне с криминалом. С помощью лейтенанта Джима Гордона и прокурора Харви Дента он намерен очистить улицы от преступности, отравляющей город. Сотрудничество оказывается эффективным, но скоро они обнаружат себя посреди хаоса, развязанного восходящим криминальным гением, известным испуганным горожанам под именем Джокер.', 'https://upload.wikimedia.org/wikipedia/ru/f/f4/%D0%A2%D1%91%D0%BC%D0%BD%D1%8B%D0%B9_%D1%80%D1%8B%D1%86%D0%B0%D1%80%D1%8C_%282008%29_%D0%BF%D0%BE%D1%81%D1%82%D0%B5%D1%80.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (6, 'Тёмный рыцарь: Возрождение легенды', 2012, 'Боевик', 4, 'Восемь лет назад Бэтмен растворился в ночи, превратившись из героя в беглеца. Приняв на себя вину за смерть прокурора Харви Дента, он пожертвовал всем. Вместе с комиссаром Гордоном они решили, что так будет лучше для всех. Пока преступность была раздавлена антикриминальным актом Дента, ложь действовала. Тем не менее, еще опаснее становится появление нового врага Бэйна, чье лицо закрыто маской. Он разворачивает в Готэме чудовищную деятельность, и это вынуждает Брюса Уэйна выйти из импровизированного изгнания. Однако даже надев свой костюм, Бэтмен может проиграть Бэйну. Но с появлением хитрой воровки по прозвищу Женщина — Кошка с загадочным прошлым всё меняется.', 'https://upload.wikimedia.org/wikipedia/ru/8/83/Dark_knight_rises_poster.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (7, 'Гонка (Rush)', 2013, 'Драма', 5, '1970-е. Два непримиримых соперника в гонках «Формула-1» — обаятельный плейбой-англичанин Джеймс Хант и дисциплинированный перфекционист-австриец Ники Лауда — доводят себя до предела физической и психологической выносливости ради победы. Каждый из них стремится быть первым, а ошибка на трассе может стоить гонщикам жизни.', 'https://upload.wikimedia.org/wikipedia/ru/thumb/f/fb/Rush.jpg/250px-Rush.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (8, 'Гран Туризмо', 2023, 'Драма', 4, 'История об исполнении желаний подростка, игравшего в Gran Turismo, чьи игровые навыки позволили выиграть серию соревнований Nissan, чтобы стать настоящим профессиональным гонщиком. Основано на реальной истории.', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRKfv7CEfymfys9CkQ2k82hmo-qDX3UOHRTUvVMWd2M_Q&s=10', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (9, 'Форд против Феррари', 2019, 'Драма', 5, 'В начале 1960-х Генри Форд II принимает решение улучшить имидж компании и сменить курс на производство более модных автомобилей. После неудавшейся попытки купить практически банкрота Ferrari американцы решают бросить вызов итальянским конкурентам на трассе и выиграть престижную гонку 24 часа Ле-Мана. Чтобы создать подходящую машину, компания нанимает автоконструктора Кэррола Шэлби, а тот отказывается работать без выдающегося, но, как считается, трудного в общении гонщика Кена Майлза. Вместе они принимаются за разработку впоследствии знаменитого спорткара Ford GT40.', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQNNebdiFxmHyjajvvRzgolgWl6p7UiDeCctTNwHqamnNhTnV54x2nxCFtguNmOUInvCJKtvUpsFyuifwA6n6KpijmV5w1BxR3fkqeaVg&s=10', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (10, 'Need for Speed', 2014, 'Боевик', 4, 'Отсидев в тюрьме за преступление, которого он не совершал, автомеханик и уличный гонщик Тоби выходит на свободу, и полон решимости поквитаться с тем, кто его подставил.', 'https://upload.wikimedia.org/wikipedia/ru/thumb/3/30/Need_for_Speed_poster.jpg/250px-Need_for_Speed_poster.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (11, 'Ущелье (The Gorge)', 2025, 'Фантастика', 4, 'Два агента высшей квалификации сближаются, когда их назначают охранять противоположные стороны загадочного ущелья. Зло, таящееся на дне ущелья, вырывается наружу, и они должны объединиться, чтобы выжить.', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSdaKAac-eAOk6CkhWjVnmS_ClC4R_bo9082XLEz2-dGBCHZpOpJFx_1nxs&s=10', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (12, 'Голод (The Hunger)', 2023, 'Ужасы', 3, 'Аой становится шеф-поваром. Она относится к своим новым обязанностям со страхом, переживает, что может разочаровать клиентов. Девушка должна будет работать с великими мастерами, которые не привыкли проигрывать. Тут появляется ещё один ресторан, и он может создать большую конкуренцию. Путь Аой пересекается с шеф-поваром заведения. Этот человек внешне приятен, вот только внутри скрывает немало тайн и жаждет уничтожить бизнес девушки…', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRa09nGvNHq4RzgITn3frPORfeZ6crMUuScPSQYFDc3tA&s=10', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (13, 'F1', 2025, 'Драма', 4, 'Легенду автоспорта Сонни Хейса уговаривают возглавить отстающую команду «Формулы-1» и обучить молодого одаренного гонщика, заодно получая последний шанс на искупление.', 'https://avatars.mds.yandex.net/get-kinopoisk-image/10835644/e07d6e9d-ccea-4117-9f0a-e05dedd11d36/600x900', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (14, 'Сволочи', 2012, 'Боевик', 4, 'Главной интригой фильма «Сволочи» Александра Атанесяна стал праздный, по сути, вопрос — а правда ли все это? Ничего неправдоподобного события на экране не содержат, и, если секретных лагерей по тренировке малолетних диверсантов, «Сталин-югентов», не было, то их бы стоило выдумать. По крайней мере, в кино. «Сволочи» удивительным образом словно исправляют ошибки, допущенные создателями в «9 роте». «Сволочи» — это не просто история о том, как мальчишек выдернули с гражданки, долго и нудно учили ползать и бегать...', 'https://image.tmdb.org/t/p/w500/bmaEpAg3OTPUH4OqS2s2wdInN0P.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (15, 'Выкрутасы', 2011, 'Комедия', 4, 'Комедия о том, как Слава Колотилов, учитель русского языка из маленького городка и Надя — успешная москвичка, случайно познакомившись в столице, через неделю совместных приключений влюбились так сильно, что решили, не откладывая, пожениться. Слава спешил на поезд, который должен был отвезти его на свадьбу в Москву, но прямо на вокзале большой чиновник отобрал у него паспорт и насильно назначил тренером детской футбольной команды.', 'https://image.tmdb.org/t/p/w500/wDCfAioYJuz4DmY7yjKlzleRLVH.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (16, 'Хардкор', 2015, 'Боевик', 4, 'Прекрасная супружеская жизнь рядом с очаровательной Эстель - это все, что помнит главный герой после того, как просыпается в неизвестной научной лаборатории, где в чувства его приводит собственная жена. Но супруга тут же оказывается похищенной, и ничего не понимающий главный герой Генри уже вынужден преследовать монстра Акана, который украл его жену. Теперь ради достижения цели Генри готов на многое. Но позже оказывается, что не только он один является врагом для Акана. У подозрительного Джимми тоже свои планы на злодея. Теперь вместе ребятам предстоит спасти Эстель и предотвратить попытку задействовать армию киборгов в борьбе с человечеством. Им предстоит бороться с самим воплощением зла.', 'https://image.tmdb.org/t/p/w500/jC0PzGjVfzvyri5UcQrUwwz6otm.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (17, 'Скуби-Ду (2002)', 2002, 'Комедия', 3, '2 года спустя после того, как "Тайная Корпорация" распалась из-за возникших противоречий, всю команду вызывают на зловещий остров, чтобы они начали расследование серии паранормальных явлений. Скуби-Ду и его команде придётся преодолеть личные разногласия и по-новому взглянуть на мнимых вампиров и нереальных привидений.', 'https://image.tmdb.org/t/p/w500/7HxMjLQt6GY6VHWungktPmkridk.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (18, 'Скуби-Ду 2', 2004, 'Комедия', 3, 'На этот раз Скуби-Ду и его приятелям предстоит сразиться с замаскированным злодеем, который замышляет захватить город Кулсвиль, наводнив его привидениями. Эти существа, появляющиеся на свет благодаря специальной машине по генерированию монстров, должны устроить в городке настоящий переполох. Но благодаря усилиям «Тайной корпорации» Кулсвиль будет непременно спасён!', 'https://image.tmdb.org/t/p/w500/2Kd5AnEpUBnBKY1EE0khxLzZSGR.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (19, 'Скуби-Ду (ТВ-фильм 2009)', 2009, 'Комедия', 2, '2 года спустя после того, как "Тайная Корпорация" распалась из-за возникших противоречий, всю команду вызывают на зловещий остров, чтобы они начали расследование серии паранормальных явлений. Скуби-Ду и его команде придётся преодолеть личные разногласия и по-новому взглянуть на мнимых вампиров и нереальных привидений.', 'https://image.tmdb.org/t/p/w500/7HxMjLQt6GY6VHWungktPmkridk.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (20, 'Мармадюк', 2010, 'Комедия', 2, 'Семья переезжает в новый дом и новым соседям придется привыкнуть к тому, что датский дог по имени Мармадюк вносит постоянный хаос в их жизнь — его хозяева к этому уже давно привыкли.', 'https://image.tmdb.org/t/p/w500/fjxmLxW0Oh9thXMkAqXnG94MKjc.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (21, 'Брат', 1997, 'Драма', 5, 'Демобилизованный из армии, Данила Багров вернулся в родной городок. Но скучная жизнь российской провинции не устраивала его, и он решился податься в Петербург, где по слухам уже несколько лет процветает его старший брат. Данила нашёл брата. Но всё оказалось не так просто — брат оказался наёмным убийцей...', 'https://image.tmdb.org/t/p/w500/1QTgAkpnPnlS6vDpA90cBL6OcRi.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (22, 'Брат 2', 2000, 'Драма', 5, 'Участвуя в программе на телевидении, Данила Багров встречает своих друзей по Чечне. Одного из них внезапно убивают. Данила знает, что у убитого были неприятности из-за брата — хоккеиста, играющего за американский клуб. Данила должен разобраться. Он вылетает в Америку и для компании берёт с собой брата. Теперь его фотография ходит по рукам русской и американской мафии. Новоявленные «Аль Капоне» понимают, что нарвались на профессионала…', 'https://image.tmdb.org/t/p/w500/x6iASprSv0kKxcEKZAqjzN6aNDS.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (23, 'Интерстеллар', 2014, 'Фантастика', 5, 'Когда засуха, пыльные бури и вымирание растений приводят человечество к продовольственному кризису, коллектив исследователей и учёных отправляется сквозь червоточину в путешествие, чтобы превзойти прежние ограничения для космических путешествий человека и найти планету с подходящими для человечества условиями.', 'https://image.tmdb.org/t/p/w500/vReLRjDV9XPhiOSEW7QWow4DXwf.jpg', 5, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (24, 'Форсаж 1', 2001, 'Боевик', 4, 'Его зовут Брайан, и он — фанатик турбин и нитроускорителей. Его цель — быть принятым в автобанду легендарного Доминика Торетто, чемпиона опасных и незаконных уличных гонок. Но это лишь часть правды… Брайан также полицейский, имеющий задание войти в доверие к Торетто, подозреваемому в причастности к дерзким грабежам трейлеров, совершенным прямо «с колес».Но чем больше доверяет нахальному новичку харизматичный Доминик, тем больше проникается герой идеалами «ангелов дорог». И тем меньше ему хочется выполнять свою миссию. И вот, наступает момент, когда Брайану придется выбирать между дружбой и долгом. И выбирать на скорости в 200 километров в час…', 'https://image.tmdb.org/t/p/w500/cHNzdyLZDZ25qRS6Uq3dXKhJJbv.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (25, 'Форсаж 2', 2003, 'Боевик', 3, 'Короткометражная предыстория второй части франшизы, которая показывает, как именно Брайн О''коннер пересёк едва различимую черту. Ещё вчера он был тайным секретным агентом, работающим на правительство, а сегодня стал самоуверенным стритрейсером, скрывающимся от правосудия.', 'https://image.tmdb.org/t/p/w500/cmhFOjy47UqrOafl0oQiygcJ7oT.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (26, 'Форсаж 3: Токийский дрифт', 2006, 'Боевик', 3, 'Шон Босуэлл — одинокий парень, который хочет казаться профи уличных гонок. Он бесшабашно гоняется по улицам города, пытаясь убежать от жизненных невзгод и наживая себе врагов среди местных властей. Когда Шону грозит тюрьма, его от греха подальше отсылают к отцу — профессиональному военному, который служит на военной базе в Японии.В незнакомой стране, живущей по своим законам, Шон чувствует себя еще большим изгоем. Однако вскоре его американский приятель Твинки знакомит его с миром подпольного дрифт-рейсинга. Раньше Шон просто тупо гонялся по улицам, а здесь перед ним открылся целый мир своеобразного искусства из металла и резины, дороги которого оказались невообразимо круты на поворотах…', 'https://image.tmdb.org/t/p/w500/qkCOHIXI2vSXsuA0psYghM9Og2U.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (27, 'Форсаж 4', 2009, 'Боевик', 4, 'Когда кривая дорожка заставляет скрывающегося от правосудия Дома Торетто вернуться в Лос-Анджелес, вражда с агентом Брайаном О’Коннером вспыхивает с новой силой. Но у парочки обнаруживается общий противник, и Дому с Брайаном приходится заключить перемирие в надежде одержать над ним победу. Грабя конвои, роя подкопы и пересекая границы, они приходят к идеальной форме отмщения — педали газа, вдавленной до упора.', 'https://image.tmdb.org/t/p/w500/A0HOGMFp4mphOCqwt5YNWbuSMJe.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (28, 'Форсаж 5', 2011, 'Боевик', 5, 'Бывший полицейский Брайан О`Коннер вместе с бывалым лихачом Домиником Торетто совсем немного увлеклись жизнью вне закона. После того, как Брайан и Миа Торетто освободили Доминика, они не рискуют долго задерживаться на одном месте, так как являются желанной целью порядком недовольных копов.', 'https://image.tmdb.org/t/p/w500/A9Ud0VPQKLPKvHXnfWGvs26jBsr.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (29, 'Форсаж 6', 2013, 'Боевик', 4, 'После того как Доминик и Брайн побывали в Рио, где они ограбили и свергли империю вора в законе, их команда получила 100 миллионов, и наши герои оказались разбросаны по всему миру. Но их привычка вечно жить в бегах не даёт им покоя. Между тем, Хоббс отслеживал организацию смертельно опасных наёмников-водителей по двенадцати странам. Единственный способ остановить эту криминальную группу — это превзойти их на улицах, поэтому Хоббс просит Дома собрать его элитную команду в Лондоне. За это он обещает полное помилование для Доминика и его друзей, чтобы они смогли наконец вернуться домой к своей семье.', 'https://image.tmdb.org/t/p/w500/qsWinjrA5wZbFtcU87EIgpCo0Xm.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (30, 'Форсаж 7', 2015, 'Боевик', 4, 'Они покорили Токио и Рио, Лос-Анджелес и Лондон. Но мир больше не играет по их правилам. Зной арабских пустынь, неприлично высокие небоскребы, миллионы долларов на колесах и очень, очень знаменитый злодей. Скорость не знает границ.', 'https://image.tmdb.org/t/p/w500/i5A0OCxcinzkcxvesvefFu9vX3K.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (31, 'Форсаж 8', 2017, 'Боевик', 3, 'Пристегните ремни — гонка продолжается. Гавана, Берлин, Нью-Йорк, для самой крутой команды в мире нет ничего невозможного, пока они вместе. Но когда на их пути окажется одна из самых красивых женщин на планете и по совместительству королева киберпреступности, дороги друзей разойдутся…', 'https://image.tmdb.org/t/p/w500/mMG9uMqEosiIMjliiPHsyycPcIA.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (32, 'Форсаж 9', 2021, 'Боевик', 3, 'Доминик Торетто ведет спокойную жизнь вместе с Летти и сыном Брайаном, но новая опасность всегда где-то рядом. В этот раз Доминику придется встретиться с призраками прошлого, если он хочет спасти самых близких. Команда снова собирается вместе, чтобы предотвратить дерзкий план по захвату мира, который придумал самый опасный преступник и безбашенный водитель из всех, с кем они сталкивались ранее. Ситуация усложняется тем, что этот человек — брат Доминика Джейкоб, которого много лет назад изгнали из семьи.', 'https://image.tmdb.org/t/p/w500/3Abag0sIPHTLFIP2asXcC7E0QxP.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (33, 'Форсаж 10', 2023, 'Боевик', 3, 'Дом Торетто и его семья становятся мишенью для мстительного сына наркобарона Эрнана Рейеса.', 'https://image.tmdb.org/t/p/w500/MSc1kcaHXvvyGgoyjDa60jxdqq.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (34, 'Джон Уик 4', 2023, 'Боевик', 5, 'Джон Уик находит способ одержать победу над Правлением Кланов. Однако, прежде чем он сможет заслужить свою свободу, ему предстоит сразиться с новым врагом и его могущественными союзниками...', 'https://image.tmdb.org/t/p/w500/o29otcx30U3EkqNVGC2feJVz5yr.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (35, 'Хоббит 1: Нежданное путешествие', 2012, 'Фантастика', 4, 'Бильбо Бэггинс, готовящийся отметить 111-ый день рождения, пишет книгу о своих приключениях 60-летней давности и уходит в воспоминания. Рассказ начинается с того, как хоббит, ни разу не покидавший родные земли, поддаётся на уговоры своего старого приятеля Гэндальфа Серого, отправиться в путешествие с 13-ью гномами во главе с Торином Дубощитом, которые держат путь в Эребор, откуда их когда-то давно изгнал огнедышащий дракон Смауг. Параллельно с этим в развалинах крепости Дол-Гулдур появляется могущественный некромант, угрожающий всему Средиземью.', 'https://image.tmdb.org/t/p/w500/zTnup9V8UJEG4jWULQQpyKB6Tq0.jpg', 5, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (36, 'Хоббит 2: Пустошь Смауга', 2013, 'Фантастика', 4, 'Продолжение путешествия хоббита Бильбо Бэггинса, волшебника Гэндальфа и 13 отважных гномов. Их компания обязана завершить своё путешествие к Одинокой горе. Там они должны встретиться с величайшей опасностью из всех - созданием куда более ужасающим, чем все их прошлые противники, которое проверит на прочность не только их мужество, но крепость их дружбы и правильность выбранного пути - драконом Смаугом.', 'https://image.tmdb.org/t/p/w500/ccbf6gnYwB2tMaU9EAgxCi88NEe.jpg', 5, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (37, 'Хоббит 3: Битва пяти воинств', 2014, 'Фантастика', 4, 'После гибели Смауга за сокровища Одинокой горы сходятся пять воинств: гномы, эльфы, люди, орки и варги. Древние союзы трещат под давлением жадности и страха, а попытки сохранить мир тонут в нарастающем хаосе. Когда битва становится неизбежной, на первый план выходят честь, верность и личный выбор. Исход сражения определяет будущее этих земель.', 'https://image.tmdb.org/t/p/w500/19fnHQ9g3Sy87rHKtw3wqhkBGOh.jpg', 5, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (38, 'Человек-паук (Тоби 1)', 2002, 'Боевик', 4, 'После укуса генетически изменённого паука, застенчивый школьник Питер Паркер обнаруживает у себя невероятные способности: сверхчеловеческую силу, ловкость и умение передвигаться по городу на паутине. Решив использовать свой дар во благо, он становится Человеком-пауком и начинает защищать жителей Нью-Йорка от преступности. Но настоящим испытанием для героя становится появление опасного Зелёного гоблина - могущественного противника, который угрожает всему городу и заставляет Питера сделать непростой выбор между личной жизнью и ответственностью, которую несут его новые способности.', 'https://image.tmdb.org/t/p/w500/uxNYgyfM9zeIQevvLON8zlPLocS.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (39, 'Человек-паук (Тоби 2)', 2004, 'Боевик', 4, 'Питер пытается совмещать обычную жизнь, учёбу и обязанности Человека-паука, но постоянные жертвы начинают разрушать его отношения с близкими. Когда талантливый учёный Отто Октавиус превращается в опасного Доктора Осьминога, городу вновь требуется его защитник. Питеру предстоит сделать трудный выбор между личным счастьем и ответственностью, ведь иногда быть героем значит отказаться от того, чего хочешь больше всего.', 'https://image.tmdb.org/t/p/w500/VBS4TFi0R7nhrPeDAc6TmBt8XC.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (40, 'Человек-паук (Гарфилд 1)', 2012, 'Боевик', 4, 'В детстве Питер Паркер был оставлен своими родителями, и поэтому воспитывался дядей и тётей. Шли годы, Питер был обычным примерным школьником, подвергался нападкам хулиганов и был влюблён в свою одноклассницу Гвен Стэйси, которая сама втайне отвечала ему взаимностью. Но после укуса генетически изменённого паука, Питер получает невероятные сверхспособности и его жизнь меняется навсегда.  Однако его не перестаёт мучить вопрос о том, что случилось с его родителями. Он знакомится с давним другом и партнёром своего отца — генетиком Куртом Коннорсом, который вместе с отцом Питера разрабатывал формулу регенерации. Питер помогает её закончить, а Коннорс, всю жизнь мечтавший восстановить свою правую руку, вводит формулу себе и становится Ящером. Осознавая свою вину, Питер начинает новую жизнь в образе таинственного супергероя Человека-паука и становится грозой преступников, одновременно пытаясь найти способ остановить Коннорса.', 'https://image.tmdb.org/t/p/w500/kby3x8wic9Lx4qEfstLu2vFHTVj.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (41, 'Такси 1', 1998, 'Комедия', 4, 'Молодой таксист Даниэль помешан на быстрой езде. Как ураган проносится он по извилистым улицам Марселя на своем мощном ревущем звере «Пежо», пугая пассажиров и прохожих. Неподкупный полицейский Эмильен вынуждает его помочь в поимке банды грабителей, ускользающих от полиции на своих неуловимых «Мерседесах». И до самого конца не ясно, кто же сможет удержаться на крутом вираже…', 'https://image.tmdb.org/t/p/w500/3I83PHvy6iPqtzuItLaI2DdLeHQ.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (42, 'Такси 2', 2000, 'Комедия', 4, 'Во Францию прибывает министр обороны Японии. Цель его визита — ознакомиться с французским опытом борьбы с терроризмом и подписать «контракт века» о взаимном сотрудничестве.Неожиданно во время показательных выступлений французской полиции министра обороны похищает гангстерская группировка «Якудза», желающая сорвать заключение наиважнейшего контракта. Даниэль и Эмильен отправляются на поиски высокого гостя. В дело вступает уже хорошо знакомое нам такси…', 'https://image.tmdb.org/t/p/w500/a4qIdcdy0xhhAsqBAHckaSYNiVG.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (43, 'Такси 3', 2003, 'Комедия', 3, 'Банда Санта-Клаусов терроризирует Марсель в канун Рождества, обещая обчистить город до основания. Комиссар полиции уже задумал провести крупномасштабную операцию под кодовым названием "Снеговик", в которой главная роль отведена таксисту Даниелю и полицейскому Эмильену. Но как бы наши друзья не натворили куда больший вред, чем сами преступники, ведь чтобы поймать "Дедов Морозов" друзья вытворяют на своем такси такое!', 'https://image.tmdb.org/t/p/w500/eK3II8goQMZV2lfyPLPPWVoASUu.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (44, 'Такси 4', 2007, 'Комедия', 3, 'Преступника № 1 транспортируют из Бельгии в Конго. .. через Марсель. Всего несколько часов самый опасный человек в мире, надежно упакованный в скафандр и железную клетку, должен пробыть в полицейском участке комиссара Жибера. Но стеречь преступника доверили Эмильену… Петра внедрится в банду и очарует злодея, Жибер задаст жару бандитам и покажет, как настоящие французы играют в футбол. И, конечно, полицейским Марселя опять не обойтись без помощи Даниеля и его реактивного такси.', 'https://image.tmdb.org/t/p/w500/t3ZUrXwmTjeLjPWkLWdlH5BVhwj.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (45, 'Лёд 1', 2018, 'Драма', 4, NULL, 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRQJN4uwBTNky78lhu747FvyDi45Y46xaHsOux8BddRpQmuxTJkwNd9aqbYHcpcTPV9vxjChpqRM5T0aAE_jp1TOWPUUMwWKvPNvTv3roOo&s=10', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (46, 'Лёд 2', 2020, 'Драма', 3, 'Что происходит в сказках после свадьбы принца и принцессы? Фигуристка Надя и хоккеист Саша поженились и больше всего на свете мечтают о ребёнке. Правда, цена, которую им придётся заплатить за эту мечту, будет невообразимо высока. Кажется, что после таких потрясений рассчитывать на счастливый конец уже невозможно. Но если вы так думаете, вы ничего не знаете о настоящих сказках...', 'https://image.tmdb.org/t/p/w500/ovwa5I70Mh2owkEGZW8HBR1JMxf.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (47, 'Матрица', 1999, 'Фантастика', 5, 'Жизнь Томаса Андерсона разделена на две части: днём он — самый обычный офисный работник, получающий нагоняи от начальства, а ночью превращается в хакера по имени Нео, и нет места в сети, куда он бы не смог проникнуть. Но однажды всё меняется. Томас узнаёт ужасающую правду о реальности.', 'https://image.tmdb.org/t/p/w500/kEDbym5htJgDQNenjUtSJxAHysB.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (48, 'Бойцовский клуб', 1999, 'Триллер', 5, 'Сотрудник страховой компании страдает хронической бессонницей и отчаянно пытается вырваться из мучительно скучной жизни. Однажды в очередной командировке он встречает некоего Тайлера Дёрдена — харизматического торговца мылом с извращенной философией. Тайлер уверен, что самосовершенствование — удел слабых, а единственное, ради чего стоит жить, — саморазрушение. Проходит немного времени, и вот уже новые друзья лупят друг друга почем зря на стоянке перед баром, и очищающий мордобой доставляет им высшее блаженство. Приобщая других мужчин к простым радостям физической жестокости, они основывают тайный Бойцовский клуб, который начинает пользоваться невероятной популярностью.', 'https://image.tmdb.org/t/p/w500/66RvLrRJTm4J8l3uHXWF09AICol.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (49, 'Джентльмены', 2019, 'Боевик', 5, 'Один ушлый американец ещё со студенческих лет приторговывал наркотиками, а теперь придумал схему нелегального обогащения с использованием поместий обедневшей английской аристократии и очень неплохо на этом разбогател. Другой пронырливый журналист приходит к Рэю, правой руке американца, и предлагает тому купить киносценарий, в котором подробно описаны преступления его босса при участии других представителей лондонского криминального мира — партнёра-еврея, китайской диаспоры, чернокожих спортсменов и даже русского олигарха.', 'https://image.tmdb.org/t/p/w500/vWxVVECgYDPSg5o0Rhw5u7KFa7X.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (50, 'Золото Рейна', 2023, 'Драма', 4, 'Настоящей школой для маленького Гивара были улицы. Повзрослев, он становится вышибалой и дилером, но однажды теряет крупную партию товара. Тогда вместе с сообщниками он похищает из инкассаторского фургона золото на 1,7 млн. евро. Золото словно испаряется в воздухе, а парень попадает в тюрьму. И превращается в самого известного гангста-рэпера Германии — Xatar.', 'https://image.tmdb.org/t/p/w500/nb4cBZuwlSeqU9lCiHkbxzAsL26.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (51, 'Рокки', 1976, 'Драма', 5, 'Кто такой Рокки Бальбоа? — это человек легенда, застенчивый, но чрезвычайно упрямый и талантливый боксер, который не щадил себя и поднялся с самого дна на вершину славы. Своим обаянием он завоевывает сердца миллионов, а кровавыми поединками шокирует даже профессионалов. Он изматывает себя изнурительными тренировками и мечтает о поясе чемпиона мира. Как бультерьер он набрасывается на своих противников, какими бы опасными они не были. Ему наплевать, что его лицо превращается в кровавое месиво, он всегда идет до самого конца, и кажется, что он скорее умрет, чем покажет свою слабость.', 'https://image.tmdb.org/t/p/w500/7gtCLTReKHDySOnPduWwu6190pt.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (52, 'Крид', 2015, 'Драма', 5, 'В центре внимания сын Аполло Крида — первого серьёзного соперника Рокки Бальбоа на ринге, в последствие ставшего лучшим другом героя. Молодой человек не испытывает никакой страсти к боксу, впрочем, и его семья не желает видеть парня в ипостаси бойца. Тем не менее, талант отца в какой-то момент проявляется и в Криде-младшем, и юноша отправляется на поиски наставника, коим для него в итоге становится постаревший Рокки, тоже не слишком жаждущий возвращаться к старым делам. Даже в качестве тренера.', 'https://image.tmdb.org/t/p/w500/ziHzbNn684Odb138qUR16xydhmi.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (53, 'Крид 2', 2018, 'Драма', 4, 'Фильм рассказывает о возвращении на ринг боксёра Адониса Крида, тренером которого выступает легендарный Рокки.', 'https://image.tmdb.org/t/p/w500/1FZuRgUP3fPG5CD9sTNHaWK62qb.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (54, 'Крид 3', 2023, 'Драма', 4, 'На свободу после длительного тюремного заключения выходит друг детства Крида и бывший вундеркинд бокса Дэмиан «Дама» Андерсон, который горит желанием доказать, что заслуживает своего шанса на ринге. Чтобы свести счёты, Донни должен поставить на карту своё будущее, ведь Дэмиану нечего терять.', 'https://image.tmdb.org/t/p/w500/2y0c8NmNKpsFvTCInjRmCEjZtCZ.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (55, 'Левша', 2025, 'Драма', 4, 'Мать-одиночка приезжает в Тайбэй, чтобы зарабатывать на жизнь: женщина открывает лапшичную на оживленном ночном рынке. Вместе с ней в мегаполис приезжают её дети: девочка-подросток и малышка-левша. Им предстоит пройти сложный путь адаптации к новому месту и преодоления конфликтов, чтобы сохранить семью. Однажды дедушка девочек говорит, что малышка-левша никогда не должна пользоваться «дьявольской» рукой, и это случайное событие приоткрывает семейные тайны.', 'https://image.tmdb.org/t/p/w500/jBlgYnAF4UdLhsgMx39IvhArOuZ.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (56, 'Бойка: Неоспоримый', 2023, 'Боевик', 3, 'Бойка пробует силы в высшей лиге боев без правил, однако случайная смерть на ринге заставляет его усомниться во всем, во что он верил. Когда он узнает, что жена человека, которого он случайно убил, в беде, Бойка решает принять участие в серии невероятных битв, чтобы освободить ее.', 'https://image.tmdb.org/t/p/w500/qAyjIwzPwoeOCDCY6CfDR1yedTI.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (57, 'Перевозчик 3', 2008, 'Боевик', 3, 'После своих последних приключений в Майами, Фрэнк Мартин решил поменять работу «перевозчика» на спокойную и уединенную жизнь во французской Ривьере. Но его планам не суждено было сбыться, когда к нему обратился бывший солдат из отряда «Дельта» Йонас Джонсон. Он рассказал, что по заказу корпорации «Ecocorp», занимающейся переработкой и утилизацией отходов, похищена Валентина — дочь украинского министра по охране окружающей среды Леонида Фазилева', 'https://image.tmdb.org/t/p/w500/aGPRarrjqoBDdWNKJrz8eVZANuA.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (58, 'Терминатор 1', 1984, 'Фантастика', 5, 'В 2029 году, в разгар войны между людьми и роботами, машины-убийцы с помощью суперкомпьютера «Скайнет» отправили в прошлое, в 1984 год, киборга-терминатора, который должен был убить женщину по имени Сара Коннор, чтобы не появился на свет её сын, возглавивший в будущем восстание против роботов. Вслед за киборгом в 1984 год отправился и Кайл Рис, задача которого - остановить терминатора любой ценой!', 'https://image.tmdb.org/t/p/w500/hcItc8IMO0WKyRWPGkI6xtKVu6X.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (59, 'Терминатор 2', 1991, 'Фантастика', 5, 'Прошло более десяти лет с тех пор, как киборг из 2029 года пытался уничтожить Сару Коннор — женщину, чей будущий сын выиграет войну человечества против машин. Теперь у Сары родился сын Джон и время, когда он поведёт за собой выживших людей на борьбу с машинами, неумолимо приближается. Именно в этот момент из постапокалиптического будущего прибывает новый терминатор — практически неуязвимая модель T-1000, способная принимать любое обличье. Цель нового терминатора уже не Сара, а уничтожение молодого Джона Коннора. Однако шансы Джона на спасение существенно повышаются, когда на помощь приходит перепрограммированный сопротивлением терминатор предыдущего поколения. Оба киборга вступают в смертельный бой, от исхода которого зависит судьба человечества.', 'https://image.tmdb.org/t/p/w500/67MopMcqqke4sJmcOwY5zu3kmYz.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (60, 'Три метра над уровнем неба 1', 2010, 'Драма', 4, NULL, 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQAU478in29_ZAUORDcUQ_ImvIjsdkkNhmVaXaLf9FG8sm_YmeGofzWYCP3agp29poXsDuypS8Xkh926H9XonKoilsVs2oeRQmF_mDlb3Y8mA&s=10', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (61, 'Три метра над уровнем неба 2', 2012, 'Драма', 3, 'Проведя два года в Лондоне, Аче возвращается домой, чтобы начать новую жизнь: устроиться на работу, завести новых друзей. Однако многое изменилось и встреча с Джин заставляет Аче почувствовать то, что он чувствовал только к Баби — своей первой большой и настоящей любви…', 'https://image.tmdb.org/t/p/w500/zvsCvPtXjs7Vh1wfcmmRTAn7Y0F.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (62, '8 миля', 2002, 'Драма', 4, 'Детройт, 90-ые. Джимми Смит-младший — молодой парень, работающий на фабрике. Он живёт на севере неблагополучного района 8 миля вместе со своей матерью-алкоголичкой, её жестоким бойфрендом и младшей сестрой. Единственная мечта Джимми — найти собственное звучание и стать популярным рэп-исполнителем. Выступления на музыкальных сценах Детройта приводят к падениям и взлётам, обостряя сильнейшую внутреннюю борьбу.', 'https://image.tmdb.org/t/p/w500/1016JRRJNu6QlOmcnEycOdBREQP.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (63, 'Поток (Flow)', 2024, 'Мультфильм', 5, 'Кот просыпается в мире, погруженном в воду, где не осталось людей. Ему удается найти убежище на лодке вместе с другими животными, однако ужиться с ними оказывается ещё сложнее, чем преодолеть свой страх воды. Но каждому предстоит научиться жить с теми, кто отличается от них, и адаптироваться к новому дивному миру.', 'https://image.tmdb.org/t/p/w500/aaYXE9KZ8yea47OxZeFHvHU6Cqg.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (64, 'Мадагаскар 1', 2005, 'Мультфильм', 5, 'Четверо изнеженных животных из Центрального зоопарка в Нью-Йорке - лев Алекс, зебра Марти, жираф Мелман и гиппопотамиха Глория - решаются на побег. Оказавшись после кораблекрушения на экзотическом острове Мадагаскар, населенном лемурами и поедающими их фоссами, путешественники с ужасом понимают, что с городскими привычками им придется распрощаться. Здесь нет людей, любимых клеток, вкусной кормежки. Начинается шоу «Последний герой» только с животными - нашим друзьям нужно выжить в непривычной среде обитания, где на каждом шагу подстерегает опасность.', 'https://image.tmdb.org/t/p/w500/vwPFZT7tS8b9zDSN0PdvOzeGlfW.jpg', 5, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (65, 'Мадагаскар 2', 2008, 'Мультфильм', 4, 'Полная опасностей жизнь на Мадагаскаре не оправдала ожиданий привыкших к комфорту Нью-Йоркского зоопарка животных — льва Алекса, зебры Марти, жирафа Мелмана и бегемотихи Глории — и друзья решают сбежать с острова. По случайности, всю компанию заносит в Африку, где Алекс встречает свою семью, с которой он был разлучён в детстве. Неожиданно для себя Алекс понимает, что после жизни в зоопарке у него гораздо меньше общего с родственниками, чем ему хотелось бы…', 'https://image.tmdb.org/t/p/w500/rfwloSBRAZCrWwsJcXd1iveI59n.jpg', 5, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (66, 'Мадагаскар 3', 2012, 'Мультфильм', 4, 'Лев Алекс, зебра Марти, бегемотиха Глория и жираф Мелман, а также король Джулиан, Морис, Морт и Пингвины всё ещё пытаются вернуться в Нью-Йорк. На этот раз их путь пройдёт через Европу, где они откроют свой цирк.', 'https://image.tmdb.org/t/p/w500/aOKn2A1Ve0rKd6u8nTS1kXYSR65.jpg', 5, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (67, 'Пингвины Мадагаскара', 2014, 'Мультфильм', 4, '4 пингвина - Шкипер, Ковальский, Рико и Прапор, объединяются с командой «Северный ветер», помогающей беззащитным животным. Им предстоит остановить злобного осьминога, доктора Октавиуса Брайна, желающего уничтожить мир.', 'https://image.tmdb.org/t/p/w500/uovMwhOMMF31sO9TxGvqjIGvdm8.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (68, 'Скуби-Ду на острове зомби', 2006, 'Мультфильм', 4, 'Команда Скуби-Ду должна разгадать ужаснейшую тайну — на острове поселился призрак — головорез, не дающий никому покоя, и от него надо избавиться. Но монстр оказался не единственным, кто встретился им на пути, — там бродят существа и пострашнее.', 'https://image.tmdb.org/t/p/w500/3jD9uxP7Jgf9hFVbvjGl5zSaAtn.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (69, 'Скуби-Ду и призрак ведьмы', 2012, 'Мультфильм', 3, 'Когда компания друзей знакомится со знаменитым автором романов ужасов Беном Рэйвенкрофтом, он приглашает их в свой родной город на осенний Праздник урожая. Все оборачивается загадочным приключением: в городке обитает привидение одного из предков Бена — знаменитой Сары.', 'https://image.tmdb.org/t/p/w500/7QdF1SKEIBtlkJZtkWM4qekwEtG.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (70, 'Скуби-Ду и кибергонка', 2013, 'Мультфильм', 3, NULL, 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSRqPi5zLf2LgjBYvgOJ9L0Kr-iQB50L96ijDcAyC3bEA&s=10', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (71, 'Три богатыря и Пуп Земли', 2022, 'Мультфильм', 3, 'По сказкам мы знаем, что было давным-давно, но что было ещё давным-давнее? Трём богатырям предстоит узнать ответ на этот вопрос, хоть они его и не задавали. Тут такое началось, что игогошеньки! Горыныч вдруг находит динозаврика, а Алёша Попович с Князем и конём Юлием буквально проваливаются сквозь землю. Теперь надо срочно понять, как вернуть их назад в будущее. А главное, узнать, кто или что такое загадочный Пуп Земли.', 'https://image.tmdb.org/t/p/w500/e8F5yCiXVIjlDfW6rZXqgcd1e6C.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (72, 'Три богатыря и Наследница престола', 2018, 'Мультфильм', 3, 'Князь Киевский решил назначить наследника престола, только вот незадача — кто это может быть? Родственник, друг семьи или может быть, заморская принцесса? Недолго думая, Князь-батюшка выбирает почти принцессу, а главное родственницу — племянницу Забаву. Нынче она вместе со своим мужем Елисеем получает образование в далёком Царьграде, где правит коварный Василевс. Чтобы вернуть наследницу на родные просторы за тридевять земель в спешном порядке отправляются три богатыря и, конечно же, главный придворный конь Юлий.', 'https://image.tmdb.org/t/p/w500/nZm3QBIuEFh6NDyjLosd3Rxqe5l.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (74, 'Три богатыря: Хроники параллельных миров', 2017, 'Мультфильм', 3, NULL, NULL, 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (75, 'Три богатыря на дальних берегах', 2015, 'Мультфильм', 3, 'На этот раз Алёша Попович, Добрыня Никитич и Илья Муромец, благодаря козням коварной Бабы Яги, оказываются за семью морями на острове, на котором живут туземцы и страшный Гомума. В их отсутствие купец Колыван решают вместе с Бабой-Ягой захватить царство и забрать власть у князя Киевского. На помощь незадачливому правителю приходит конь Юлий, а также жёны богатырей и их многочисленные родственники. Словом, богатырей и зрителей ждут приключения на дальних берегах, обыкновенные и невероятные.', 'https://image.tmdb.org/t/p/w500/xwybGCAeOBUwhc8jhgIzxwCUP5t.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (76, 'Три богатыря и Жена царя', 2014, 'Мультфильм', 3, NULL, NULL, 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (77, 'Три богатыря и Принцесса Елизавета', 2012, 'Мультфильм', 3, NULL, NULL, 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (78, 'Три богатыря и Земля неизвестная', 2011, 'Мультфильм', 4, NULL, NULL, 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (79, 'Три богатыря и Шамаханская царица', 2010, 'Мультфильм', 4, 'Некогда первая красавица восточных земель Шамаханская царица, мечтая вернуть себе утраченные чары, отправляется в Храм Вечной Молодости. Однако там выясняется, что для достижения цели необходимо оросить Дерево Молодости слезами тысячи красавиц. Тогда помощник царицы — Ворон подсказывает ей самый, как ему кажется, простой план, где добыть женские слёзы. Всего-то и нужно: используя магический взгляд царицы, с помощью которого она покоряет мужчин, влюбить в себя Князя Киевского, завладеть Русью и заставить плакать всех её женщин. Но тут в дело вмешиваются богатыри Алёша Попович, Илья Муромец, Добрыня Никитич, а также уже хорошо знакомые зрителю герои: конь Юлий, Змей Горыныч, бабуля и дед Тихон. Дело, по мнению богатырей, несложное, а проветриться не мешает. Но скоро, как известно, только сказка сказывается...', 'https://image.tmdb.org/t/p/w500/nc8d2RZ08H2Oo0E6pguo2ob9uns.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (80, 'Три богатыря и Наследник престола', 2009, 'Мультфильм', 3, NULL, NULL, 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (81, 'Три богатыря', 2004, 'Мультфильм', 4, 'Иван Царевич мечтает жениться на Марье Искуснице. Но Царь решил женить сына на заморской принцессе. Три богатыря помогают Марье Искуснице в ее борьбе за любовь Ивана Царевича. Они должны выполнить задание Царя и принести ему перо Жар-птицы. А заморская принцесса обращается за помощью к Бабе-Яге.', 'https://image.tmdb.org/t/p/w500/wrBJTUe7KJFPS35WMnBU55MnwaM.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (82, 'Иван Царевич и Серый Волк 1', 2011, 'Мультфильм', 4, NULL, NULL, 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (83, 'Иван Царевич и Серый Волк 2', 2013, 'Мультфильм', 4, 'В Тридевятом царстве, где живут наши герои — тишь, да благодать. Иван женился на Василисе, и «жили они долго и счастливо», да не тут-то было. Иван целыми днями пропадает с Волком на службе — укрепляет рубежи и оборонную мощь, мечтает перевести стрелки часов на семь часов назад, чтобы меньше спать, и больше работать. А Василисе — скучно, как всем девушкам, ей хочется романтики, ну, такой, как в сказках. И тогда она решает организовать своё похищение... Однако, когда такое бывало, что в сказках всё получалось так, как задумывалось?', 'https://image.tmdb.org/t/p/w500/zAN0PkWfOueVSc1QlGSY7OPQMOt.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (84, 'Иван Царевич и Серый Волк 3', 2016, 'Мультфильм', 3, 'Царь Тридевятого царства, в честь своего 150-летия решил, что с него хватит — пора на заслуженный отдых. «Я устал. Я ухожу», — заявил самодержец и с удочкой и ведёрком удалился в деревенскую глушь. А оберегать государство остались Иван с Серым Волком. Вот только Василиса, жена Ивана, заявила, что свадебного путешествия у неё не было, заграницу она не видела, «постить» в инстаграм решительно нечего и вообще. Иван спорить не стал, а вместе с Василисой, Котом — учёным и Серым Волком, погрузился на ковёр-самолёт и отправился в путь. А за главного в стране герои оставили самое обычное огородное пугало... Но пока компания шаталась по Миланам и Парижам, Пугало ожило и начало наводить свои порядки в Тридевятом царстве...', 'https://image.tmdb.org/t/p/w500/ipORigqKgeSzgqaFIZ0ewIEgqqW.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (85, 'Иван Царевич и Серый Волк 4', 2018, 'Мультфильм', 3, 'Зима в этом году в тридевятом царстве случилась особенно долгая и холодная. Прямо, как в прошлом году. И как в позапрошлом. Но, вот, пришла весна. Точнее — почти пришла. С вьюгой, морозами и снегом. Как обычно. И совсем было загрустили наши герои — Иван, Василиса, Серый Волк и Царь-батюшка, если бы вместе с почти-весной, не пришла новость — в Трисемнадцатом царстве пройдёт ежегодный всесказочный конкурс песни. В прошлом году там победил хомяк Жорж, а чей голос окажется круче на этот раз? Царь решил, что Тридевятое царство будет представлять Кот-учёный. Не один всё же мультфильм прошли вместе, да и всё равно он про книги забыл, орёт, точнее поёт целыми днями на крышах, как и положено коту в марте. И, конечно, вся компания во главе с Иваном и Волком отправляется поддержать пушистого певца. Ведь свои нужны рядом. А то шоу-бизнес — настоящий серпентарий, и кто знает, какие тёмные силы стоят за коварными соперниками и их стремлением стать звездой.', 'https://image.tmdb.org/t/p/w500/fEjOigTJ4xc4wp9P7iNE5oRenxG.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (86, 'Иван Царевич и Серый Волк 5', 2020, 'Мультфильм', 3, 'Была у Ивана с Василисой не жизнь, а сказка. Буквально. И эту сказку они уже знали, а им захотелось отправиться туда-не-знаю-когда. Вот только одна бабочка со своим эффектом крылышком махнула да устроила волшебную перезагрузку. Теперь во всём Тридевятом царстве никто не помнит даже как Ивана звать, включая саму Василису. А значит, чтобы снова добиться принцессы, Ивану с Серым Волком нужно перевернуть всю мультик-вселенную!', 'https://image.tmdb.org/t/p/w500/74f8CF18qFY4o6SquY0RJMGDPkA.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (87, 'Иван Царевич и Серый Волк: Возвращение', 2024, 'Мультфильм', 3, NULL, NULL, 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (88, 'Скуби-Ду (все сезоны)', NULL, 'Мультфильм', 4, '2 года спустя после того, как "Тайная Корпорация" распалась из-за возникших противоречий, всю команду вызывают на зловещий остров, чтобы они начали расследование серии паранормальных явлений. Скуби-Ду и его команде придётся преодолеть личные разногласия и по-новому взглянуть на мнимых вампиров и нереальных привидений.', 'https://image.tmdb.org/t/p/w500/7HxMjLQt6GY6VHWungktPmkridk.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (89, 'Форма голоса (A Silent Voice)', 2016, 'Аниме', 5, 'Молодой человек Сёя Исида внезапно осознаёт, что в школе умудрился превратить жизнь одноклассницы Сёко в ад только потому, что та была глухая. И теперь, хоть и запоздало, парень понимает — чтобы сказать нечто важное тому, кто не может тебя услышать, вовсе не обязательно использовать голос.', 'https://image.tmdb.org/t/p/w500/c0Gv8xTSEmIcQPxbhINKvkbJO8s.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (90, 'Аватар: Легенда об Аанге', 2005, 'Аниме', 5, 'Аанг, аватар и последний маг воздуха, узнаёт о древней силе, которая может спасти его культуру от исчезновения. Вместе с давними друзьями Аанг отправляется в далёкое путешествие, чтобы отыскать силу и опередить тех, кто хочет использовать её в злых целях.', 'https://image.tmdb.org/t/p/w500/cypsdXImFEVN3NOlckf9ZVrBY6M.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (91, 'Хантер × Хантер', 2011, 'Аниме', 5, 'Американское морское спецподразделение «Охотник-убийца» вступает в очередную опасную боевую авантюру по спасению мира от катастрофы.', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcS2UZBt-3rg_UlhJrwUN_mmHpP9agf83sx4wYTl3B7VMFEu4m7NDIoVgmiseZsViitEqNjfmv4rqqxbV_7_wipFo4mx8SwTtYvwYl2KEkQ&s=10', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (92, 'Токийский гуль', 2014, 'Аниме', 4, 'На студента Кэна Канэки напал гуль. Парню удалось спастись, когда на монстра упала металлическая конструкция и убила его. Обоих доставляют в больницу и Кэну пересаживают органы гуля.', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSReqCokBqXQen57qmUERxIWsHofACfL_1SAbKikPDSLQ&s=10', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (93, 'Человек-бензопила (Chainsaw Man)', 2022, 'Аниме', 5, 'Молодой охотник на демонов Дэндзи, который ждал свидания со своей возлюбленной Макимой, попадает под ливень. Укрывшись от дождя, он случайно встречает девушку по имени Резе, работающую в соседнем кафе. Та добродушно ему улыбается, и разговор становится более непринужденным. После этой встречи повседневная жизнь Дэндзи начинает меняться.', 'https://image.tmdb.org/t/p/w500/f4Bv4JWv85zHSisuq7SD2WeuJGr.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (94, 'Милый во Франксе', 2018, 'Аниме', 4, NULL, 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRW73zdhmMtDcAPeEcVvPU-yaSOVAMkxGcdmFW-UZNGIw&s=10', 5, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (95, 'Глупый свин', 2017, 'Аниме', 3, 'Сакута посещает выпускной Май и встречает ребенка, похожего на Май. Ему звонят по поводу его мамы, он видит шрам и задумывается о новом синдроме.', 'https://image.tmdb.org/t/p/w500/lmEw8tb6bn5RwQGXIQsxywm4xYS.jpg', 5, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (96, 'Безумный азарт (Kakegurui)', 2017, 'Аниме', 4, 'Хяккао — частный элитный институт, чей академический рейтинг основан на азартных играх учеников. Лучшие награждаются статусом, богатством и господством над нижними рядами. Юмэко — новичок в академии. Она не только красива, но и очень азартна.', 'https://image.tmdb.org/t/p/w500/sKrCqhBXs6I9RPMjmaOMR67ahTe.jpg', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (97, 'Фарфоровая кукла', 2016, 'Аниме', 4, NULL, NULL, 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (98, 'Во все тяжкие (Breaking Bad)', 2008, 'Сериалы', 5, 'Успешный бизнесмен всю жизнь не пил, не курил, занимался спортом, а потом однажды узнал, что смертельно болен. Теперь он решает испытать оптом все искушения и грехи родного города.', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSjeVT81woggw9mDJFeNwgHf_XkpD0WPno_i3Rucdh-jA&s=10', 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (99, '13 причин почему (13 Reasons Why)', 2017, 'Сериалы', 4, NULL, NULL, 1, '2026-07-15 06:10:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (100, 'Королева крика', 2006, 'Ужасы', 3, 'Пародия на слэшеры 90-х. Новая обитательница маленького городка оказывается в центре серии убийств.', NULL, 4, '2026-07-15 09:56:57');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (101, 'Игра престолов', 2011, 'Фэнтези', 5, 'Эпическая фэнтези-драма по мотивам книг Джорджа Мартина. Борьба за Железный трон.', 'https://image.tmdb.org/t/p/w500/4ykgUb63iIYUiLPenxqUGj4Cz37.jpg', 4, '2026-07-15 09:56:57');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (102, 'Дом дракона', 2022, 'Фэнтези', 4, 'Приквел Игры престолов. История династии Таргариенов за 200 лет до событий оригинала.', NULL, 4, '2026-07-15 09:56:57');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (103, 'Рыцарь семи королевств', 2025, 'Фэнтези', 4, 'Новый сериал во вселенной Игры престолов. Приключения рыцаря-авантюриста.', NULL, 4, '2026-07-15 09:56:57');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (104, 'Интерны', 2010, 'Комедия', 4, 'Российский ситком о врачах-интернах, которые учатся и работают в больнице.', NULL, 4, '2026-07-15 09:56:57');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (105, 'Кухня', 2012, 'Комедия', 4, 'Российский ситком о жизни поваров и персонала московского ресторана.', 'https://image.tmdb.org/t/p/w500/rFt7ByI0BeUxxn5e4uULqXXuVeo.jpg', 4, '2026-07-15 09:56:57');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (106, 'Как приручить дракона', 2010, 'Мультфильм', 5, 'Молодой викинг подружится с драконом и изменит отношение своего племени к ним.', 'https://image.tmdb.org/t/p/w500/cMUmeDM2QRlSOAK9onB8PhXtdZJ.jpg', 5, '2026-07-15 09:56:57');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (107, 'Спирит: Душа ковбоя', 2002, 'Мультфильм', 4, 'Девушка отправляется на Запад и находит свободу вместе с диким мустангом.', NULL, 4, '2026-07-15 09:56:57');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (108, 'Коты-аристократы', 2010, 'Мультфильм', 4, 'Элегантные коты из богатого дома оказываются на улицах Парижа.', 'https://image.tmdb.org/t/p/w500/8VBA5p9JG6LYfnwb2Ce8RnJFZp5.jpg', 4, '2026-07-15 09:56:57');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (109, 'Труп невесты', 2005, 'Мультфильм', 5, 'Тим Бартон. Жених случайно обручается с призраком, и его затягивают в мир мертвых.', 'https://image.tmdb.org/t/p/w500/sgqR6vsyc3SGGIjlK2HseG0vrQX.jpg', 4, '2026-07-15 09:56:57');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (110, 'Коралина в стране кошмаров', 2009, 'Мультфильм', 4, 'Тим Бартон. Девочка находит параллельный мир, который оказывается зловещей ловушкой.', 'https://image.tmdb.org/t/p/w500/kwgBclQIcghtYYoJiDTw48bHWUK.jpg', 4, '2026-07-15 09:56:57');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (111, 'Кошмар перед Рождеством', 1993, 'Мультфильм', 5, 'Тим Бартон. Король Тыквенных Голов пытается украсть Рождество.', 'https://image.tmdb.org/t/p/w500/xvqFn90FxKTJflG4n0spZY7vySu.jpg', 4, '2026-07-15 09:56:57');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (112, 'Франкенвини', 2012, 'Мультфильм', 4, 'Тим Бартон. Мальчик оживляет своего мёртвого пса с помощью науки.', 'https://image.tmdb.org/t/p/w500/pzqDbpshw50ulrSM5Sdc2AY70tq.jpg', 4, '2026-07-15 09:56:57');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (113, 'Царство небесное', 2005, 'Исторический', 5, 'Ридли Скотт. Эпическая история о крестовых походах и битве за Иерусалим.', 'https://image.tmdb.org/t/p/w500/b0TnQ4uVygCDu0h8pbKU2Xgektl.jpg', 4, '2026-07-15 09:56:57');
