INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (115, 'Человек-пила', 2023, 'Боевик', 3, 'Парень получает способность превращать части тела в пилы и сражается с демонами.', NULL, 4, '2026-07-15 09:56:57');
