INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (134, 'Красная королева', 2015, 'Фантастика', 4, 'В мире, где общество делится на крови, девушка с красными глазами скрывает свою тайну.', 'https://image.tmdb.org/t/p/w500/a9Cip58G1XZUqU2AA6wxNu0xMLP.jpg', 4, '2026-07-15 09:56:57');
