INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (141, 'Во все тяжкие', 2008, 'Драма', 5, 'Учитель химии, больной раком, начинает варить метамфетамин.', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSjeVT81woggw9mDJFeNwgHf_XkpD0WPno_i3Rucdh-jA&s=10', 4, '2026-07-15 09:56:57');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (142, '1+1 (Неприкасаемые)', 2011, 'Комедия', 5, 'Парализованный аристократ нанимает бездомного в помощники. Невероятная дружба.', 'https://image.tmdb.org/t/p/w500/zQsq95pYgjhJwYKqoFdeXlVse88.jpg', 4, '2026-07-15 09:56:57');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (143, 'Не стучи дважды', 2016, 'Ужасы', 3, 'Одинокая мать с сыном переезжает в новый дом, где таится ancient evil.', 'https://image.tmdb.org/t/p/w500/44S41lABtclQRghN6mHuyD1WUFn.jpg', 4, '2026-07-15 09:56:57');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (144, 'Следствие ведут овечки', 2021, 'Драма', 3, 'Детективный сериал о расследовании запутанных дел.', 'https://image.tmdb.org/t/p/w500/cArYRS41NKc8kEJXrGZBWCmUmBG.jpg', 4, '2026-07-15 09:56:57');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (145, 'Любовь и другие лекарства', 2010, 'Мелодрама', 4, 'Молодой фармацевтический агент влюбляется в девушку с болезнью Паркинсона.', 'https://image.tmdb.org/t/p/w500/zys6uLVuwh2o7epNMYj45cylDxl.jpg', 1, '2026-07-15 09:58:20');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (146, 'Эван Всемогущий', 2007, 'Комедия', 3, 'Эван Бакстер, которого всемогущий босс Брюс заставил лепетать всякую чушь во время прямого эфира новостей, уходит с работы на телевидении. Но жизнь его сразу же пошла в гору: он стал конгрессменом. И тут вновь появился Господь Бог, который открыл перед Эваном ужасы грядущего и попросил срочно приступить к строительству ковчега, беря пример с Ноя.', 'https://image.tmdb.org/t/p/w500/1MQ6b42fbQi0wKvBqjov5QOWQvY.jpg', 1, '2026-07-15 14:31:46');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (147, 'Моана', 2016, 'Приключения', 3, 'Моана откликается на зов океана. Впервые в жизни она отправляется за риф своего острова Мотунуи вместе с прославленным полубогом Мауи. Их ждёт незабываемое путешествие, которое должно вернуть процветание её народу.', 'https://image.tmdb.org/t/p/w500/drbVlDdeqRLoxylGpym4dECh5ai.jpg', 5, '2026-07-15 14:31:47');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (148, 'Холодное сердце', 2013, 'Мультфильм', 4, 'Принцесса Эльза из королевства Эренделл, способная с помощью магии создавать снег и лед, из-за случайной ошибки едва не убила свою сестру Анну, после чего начала вести уединённый образ жизни, изо всех сил пытаясь подавить постоянно растущую магическую силу. Когда над волшебным королевством нависает опасность вечной зимы, Анна, объединившись с суровым Кристоффом и северным оленем Свеном, отправляется на опасные поиски единственного человека, способного спасти Эренделл от неминуемой гибели - её сестры Эльзы.', 'https://image.tmdb.org/t/p/w500/5LYjyQT4IP7oM5ibawHXyDzT2Pp.jpg', 5, '2026-07-15 14:31:47');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (149, 'Храбрая сердцем', 2012, 'Мультфильм', 4, 'Испокон веков мифы и легенды окутывают загадочной пеленой живописные отроги Шотландских гор. Искусной лучнице Мериде приходится выбирать свой путь в жизни самостоятельно, и однажды она отказывается следовать древним традициям королевства, бросая вызов могущественным шотландским кланам и их предводителям: нескладному лорду МакГаффину, угрюмому лорду Макинтошу и сварливому лорду Дингволлу. Неосторожные поступки Мериды грозят повергнуть королевство в хаос, и тогда она отправляется за советом к эксцентричной отшельнице, которая вместо помощи накладывает на Мериду опасное заклятье. Юной принцессе предстоит полагаться только на собственную храбрость, чтобы преодолеть могущественное волшебство и победить самого страшного зверя из тех, что водятся в горных долинах.', 'https://image.tmdb.org/t/p/w500/lCYl7WVZfZ2oJoQCWjEyxPxpxli.jpg', 5, '2026-07-15 14:31:48');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (150, 'Терминатор 3', 2003, 'Фантастика', 3, 'Прошло десять лет с тех пор, как Джон Коннор помог предотвратить Судный День и спасти человечество от массового уничтожения. Теперь ему 25, Коннор не живет «как все» - у него нет дома, нет кредитных карт, нет сотового телефона и никакой работы. Его существование нигде не зарегистрировано. Он не может быть прослежен системой Skynet - высокоразвитой сетью машин, которые когда-то попробовали убить его и развязать войну против человечества. Пока из теней будущего не появляется T-X - Терминатрикс, самый сложный киборг-убийца Skynet. Посланная назад сквозь время, чтобы завершить работу, начатую её предшественником, T-1000, эта машина так же упорна, как прекрасен её человеческий облик. Теперь единственная надежда Коннору выжить - Терминатор, его таинственный прежний убийца. Вместе они должны одержать победу над новыми технологиями T-X и снова предотвратить Судный День...', 'https://image.tmdb.org/t/p/w500/nnZlp31UgvkRuIzSmCTHO1SkvQ.jpg', 5, '2026-07-15 14:31:48');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (151, 'Терминатор 4', 2009, 'Фантастика', 3, '2018 год. В мире наступила война с машинами. Джон Коннор — человек, чья судьба — возглавить Сопротивление электронному мозгу Скайнет и армии Терминаторов. Но в будущее, с верой в которое он возвращён, вклинивается таинственный Маркус Райт: незнакомец, чьи последние воспоминания рисуют камеру смертников. Коннор должен понять, кто такой этот Маркус и с какой целью пожаловал к людям. И на фоне подготовки Скайнетом решающего удара, Коннор и Райт отправляются в путешествие, приводящее их в самую сердцевину взбунтовавшейся операционной системы, где открывается ужасная тайна, кроющаяся за потенциальным уничтожением человечества.', 'https://image.tmdb.org/t/p/w500/irfM3I3nm9aVRN09HGQc18TJOyP.jpg', 5, '2026-07-15 14:31:49');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (152, 'Терминатор 5', 2015, 'Фантастика', 3, 'Когда Джон Коннор, лидер сопротивления, посылает сержанта Кайла Риза назад в 1984 год, чтобы защитить Сару Коннор и спасти будущее, неожиданный поворот событий создает разлом во времени. Сержант Риз оказывается в новой, незнакомой версии прошлого, где он встречает неожиданных союзников, в том числе Терминатора, новых опасных врагов, и новую миссию: изменить будущее...', 'https://image.tmdb.org/t/p/w500/eMUscX52jUbNC1xn4WJthJDUQNq.jpg', 5, '2026-07-15 14:31:49');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (153, 'Терминатор 6', 2019, 'Фантастика', 3, 'Мексика. Милая девушка Даниэла Рамос, а для друзей просто Дани, вместе с братом приходит с утра работать на завод, но там выясняется, что их вскоре заменят автоматикой. И это не единственная угроза, которую представляют для девушки машины: тут же на неё нападает присланная из будущего и практически неубиваемая модель терминатора REV-9. Но на защиту Дани встаёт Грэйс — тоже прибывшая из будущего женщина, модифицировавшая свои боевые характеристики до терминаторского уровня. Вскоре к ним на помощь придёт и Сара Коннор, которая теперь превратилась в настоящую охотницу на роботов-убийц.', 'https://image.tmdb.org/t/p/w500/ffULB4SNiMuTbEl8dGPnU185hfe.jpg', 5, '2026-07-15 14:31:50');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (154, 'Ну здравствуй, Оксана Соколова!', 2016, 'Комедия', 4, 'Актёр-неудачник по имени Илья получает работу своей мечты. Его утверждают на ведущего программы «Мужское мнение», выходящей в прайм-тайм на «Мужском радио». Наш герой устраивает вечеринку, а на утро понимает, что не может говорить - пропал голос. В панике, чтобы вернуть голос, Илья готов на всё. Он обращается к врачу, и тот делает ему сомнительный укол в голосовые связки. Врач также просит героя не разговаривать ближайшие полчаса. Илья мчится на эфир в надежде, что проблема решена…', 'https://image.tmdb.org/t/p/w500/2M1IoNadgnuPeVkXEPwKKTyAzrO.jpg', 5, '2026-07-15 14:31:50');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (155, 'Спирит: Душа прерий', 2002, 'Мультфильм', 4, 'История дикого жеребца мустанга, Спирита, путешествующего по территории всей Америки. Храбрый Спирит заводит дружбу с молодым индейцем Ручейком и находит любовь с красивой кобылой по имени Гроза.  Все счастливы до тех пор, пока на жеребца не положили глаз люди, которые хотят сделать из него военную лошадь…', 'https://image.tmdb.org/t/p/w500/rOUvDmeJFgYyR6cZwowJsRUVZS6.jpg', 5, '2026-07-15 14:31:51');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (156, 'Любовь на Бали', 2024, 'Мелодрама', 2, 'В детстве Деви слышала от бабушки легенду о проклятом ожерелье, из-за которого женщины в их роду несчастны в любви. Звучит как сказка, но Деви и впрямь не удаётся построить крепкие отношения. Её мама Корнели тоже одинока: муж давно ушёл к другой. А тут ещё и сестра Деви – бывшая звезда соцсетей Дженни – переживает болезненное расставание. После смерти бабушки разобщённая семья решает вместе поехать на родину предков в Индонезию. И, похоже, ни одно проклятие не действует на прекрасном романтическом острове Бали.', 'https://image.tmdb.org/t/p/w500/cprdP775lCiF6zlZYdVgGBj4pqn.jpg', 5, '2026-07-15 14:31:51');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (157, 'Твоё сердце будет разбито', 2026, 'Мелодрама', 4, 'Полина Туманова переводится в другую школу, где над ней начинает издеваться популярная девочка Лика Малиновская и её подруги. За новенькую вступается байкер Дима Барсов, главный местный бунтарь. Он предлагает и дальше защищать Полину, если она согласится притворяться его девушкой. В ходе этой игры у пары появляются настоящие чувства друг к другу, но их одноклассники и семья девушки находят причины, чтобы разлучить влюблённых.', 'https://image.tmdb.org/t/p/w500/naOC89qeEygU44xM9EIot1m5AUQ.jpg', 5, '2026-07-15 14:31:52');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (158, 'Дети леса', 2024, 'Мультфильм', 3, 'На первый взгляд, Караг — обычный подросток, но в его глазах скрывается удивительная тайна. Он — оборотень, наполовину человек, наполовину пума. Однажды ему выпадает шанс поступить в загадочную школу «Кристалл», где учатся подростки, умеющие превращаться в зверей. Карагу предстоит не только обрести новых друзей, но и пройти опасные испытания, узнав свое истинное предназначение.', 'https://image.tmdb.org/t/p/w500/lyqg2LUQOPjCpib2a4B6d1jUlvp.jpg', 5, '2026-07-15 14:31:53');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (159, 'Родительский дом', 2026, 'Драма', 4, 'Даша хочет продать дом, доставшийся ей по наследству от бабушки, чтобы купить квартиру в столице. Приехав в деревню, с которой связано её прошлое, она встречает свою первую любовь Мишу. Он работает простым сыроваром и вместе со своим юным племянником Петровичем превращает Дашину сделку с недвижимостью в настоящее испытание. Постепенно девушка понимает, что родной дом значит для неё намного больше денег.', 'https://image.tmdb.org/t/p/w500/uNP2DO6NreKj9trBdJ1E8ptUPUr.jpg', 5, '2026-07-15 14:31:53');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (160, 'Приключение жёлтого чемоданчика', NULL, 'Комедия', NULL, NULL, NULL, 5, '2026-07-15 14:31:54');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (161, 'Няня Оксана', NULL, 'Комедия', NULL, NULL, NULL, 1, '2026-07-15 14:31:54');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (162, 'Кузнецовы ТВ', NULL, 'Комедия', NULL, NULL, NULL, 1, '2026-07-15 14:31:55');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (163, 'На деревне дедушке', NULL, 'Комедия', NULL, NULL, NULL, 1, '2026-07-15 14:31:55');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (164, 'Плагиатор', 2025, 'Триллер', 4, 'Егору 30, его работа — подпевать гостям в караоке, но он мечтает написать свою песню, стать знаменитым и построить счастливую жизнь с Юлей вопреки желанию её отца-олигарха. Однажды Егор находит в собственном шкафу портал в 1991 год, и у него рождается гениальный план, который обеспечит ему идеальное будущее. Но каждая попытка изменить что-то в прошлом приводит к всё более неожиданным результатам, и приходится делать сложный выбор.', 'https://image.tmdb.org/t/p/w500/eLy88qL0r3d5yAZRbxxRrMUWMAg.jpg', 5, '2026-07-15 14:31:56');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (165, 'Жизнь по вызову', 2025, 'Комедия', 4, 'Александр Шмидт — серый кардинал рынка эскорт-услуг. Но просто больших денег ему уже недостаточно — он жаждет реальной власти. Амбиции Шмидта привлекают опасных людей, и на него начинает охоту международный картель. Шмидт впервые сталкивается с угрозой такого масштаба. Теперь на кону не только его бизнес, но и жизнь.', 'https://image.tmdb.org/t/p/w500/sl7f5fud3LXUt0eD2XzUgz3Ysc2.jpg', 5, '2026-07-15 14:31:56');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (166, 'Сводишь с ума', 2025, 'Мелодрама', 4, 'Алиса заселяется в просторную квартиру в Санкт-Петербурге, в которой начинает сбоить зеркало, показывая юной квартирантке параллельную реальность той же самой квартиры. Вот только проживает в этой параллельной реальности не Алиса, а тусовщик Иван. Сумеют ли молодые люди распознать настоящую любовь и по силам ли им окажется объединить свои миры, чтобы встретиться в реальности и просто прикоснуться друг к другу?', 'https://image.tmdb.org/t/p/w500/s42X4sEKtQJfLu3tps2vPMjgjrh.jpg', 5, '2026-07-15 14:31:57');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (167, 'Принц из рая', 2023, 'Фантастика', 4, 'Оливия, борющаяся с писательским кризисом после разрыва отношений, берет отпуск и проводит его в тропиках в надежде на вдохновение. Там Оливия встречает принца Александра, который ищет способ отвлечься от своего обязательства жениться на представительнице королевской семьи.', 'https://image.tmdb.org/t/p/w500/7jvRet2Sqbk1HTr4pTZb157GmS6.jpg', 5, '2026-07-15 14:31:57');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (168, 'Девка-баба', 2025, 'Комедия', NULL, 'Обычай изготовления кукол-мотанок — древний, богатый на мифы и легенды. Есть поверье, что они помогают своему владельцу. Главная героиня фильма — 12-летняя девочка-подросток, она учится в художественной школе, но не верит в свои способности и переживает кризис взросления с помощью славянской куклы. Наматывая куклу, ее хозяйка проходит некий этап взросления, формирует свой внутренний мир. Кукла порой помогает ей справиться со сложными ситуациями, а порой — наоборот.', 'https://image.tmdb.org/t/p/w500/zO8offPRgKqzdHEQ07G8MbDhG7j.jpg', 5, '2026-07-15 14:31:58');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (169, 'Беляковы в отпуске', 2024, 'Комедия', 4, 'Обычная семья Беляковых из города Таганрога приезжает на отдых в Турцию и попадает в затруднительную ситуацию: по ошибке главы семейства Сергея Белякова номера отеля оказались оплаченными на следующий год, а денег на обратную дорогу нет.  Но беда не приходит одна. В отеле Беляковы встречают обеспеченную семью Дубравиных, которым они смертельно завидуют со школьных лет, и во всём пытаются с ними конкурировать. Беляковы не могут признаться в своём провале «заклятым друзьям» и идут ва-банк...', 'https://image.tmdb.org/t/p/w500/nSXfQVP9knMz4EBBSNp0VfcGS0q.jpg', 5, '2026-07-15 14:31:58');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (170, 'Новогодний шеф', 2023, 'Комедия', 4, 'Виктор – владелец модного ресторана, вот только  дела в нём идут не очень. Вся надежда только на новогоднюю ночь, ведь все столики уже забронированы, но наступает 31 декабря и из ресторана уходит шеф-повар со всей командой. Казалось бы, всё пропало, но тут в ресторане появляется Олеся, владелица кухни на дому в подмосковном посёлке. Она привезла пирожные, которые Виктор совершенно случайно заказал у неё и даже успел забыть об этом. Виктор предлагает Олесе стать шеф-поваром на новогоднюю ночь. Она отказывается, Олеся обещала своему сыну Кириллу новогоднюю сказку с салютами. Виктор уговаривает её согласиться,  он верит в неё и  знает, что  у  Олеси есть особый дар – пробуждать у людей своими блюдами  самые лучшие воспоминания...', 'https://image.tmdb.org/t/p/w500/tm8TCgLaWDb7z51FpzlD15pAVGl.jpg', 5, '2026-07-15 14:31:59');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (171, 'Культурная комедия', 2024, 'Комедия', NULL, 'Циничный пермский чиновник Виктор Летаев курирует дорожное строительство и привык всегда добиваться своего. Он знает и любит свое дело, но не интересуется ничем другим. Его кредо: «Я колол дрова, мне было не до этих ваших Чеховых с Пастернаками, потому что дрова нужны всем, а искусством дом не согреешь». Но циничное мировоззрение меняется, когда новым вектором развития региона становятся культура и искусство. Теперь, чтобы усидеть в кресле чиновника, ему предстоит изучить культурное наследие Пермского края. В помощь себе он берет уроки у преподавателя искусствоведения Марины Николаевны. Удастся ли ей облагородить бескультурного чиновника?', 'https://image.tmdb.org/t/p/w500/7flSermzDevNaABAfQDXcImN9iu.jpg', 5, '2026-07-15 14:31:59');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (172, 'Бывший в помощь', 2024, 'Комедия', NULL, 'Лера с Германом готовятся к свадьбе. Жених собирается подарить своей невесте автомобиль. Неожиданно продавцом салона оказывается бывший парень Леры — Макс, безбашенный каскадер, подрабатывающий в автосалоне. Макс настаивает на тест-драйве и устраивает безумный форсаж, который заканчивает экстремальным торможением. В результате удара Лера забывает последний год жизни, а с ним — Германа… Теперь она считает, что ее парень — Макс. По словам врача, есть надежда, что реконструкция ярких событий из жизни с бывшим позволит вернуть Лере память. Герману приходится просить Макса о помощи — сыграть в отношения с Лерой. Но жених не оставит ситуацию без контроля — Макс должен представить Германа Лере как своего друга детства, и они втроем будут жить под одной крышей.', 'https://image.tmdb.org/t/p/w500/Czuq11IiJzEr42njq9G9SlIg9I.jpg', 5, '2026-07-15 14:32:00');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (173, 'Мужские правила моего деда', 2025, 'Комедия', NULL, 'Виктор Степанович — дед советской закалки, который не понимает и не разделяет современных «тепличных» методов воспитания детей. Обманным путем он увозит своего внука из дома, чтобы отправиться с ним в незабываемое приключение и, наконец-то, сделать из домашнего мальчика настоящего мужчину. Достойного мужа рода Богдановых.', 'https://image.tmdb.org/t/p/w500/b8sYsTYdwXNhIOxJeYspcjoaFsu.jpg', 5, '2026-07-15 14:32:00');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (174, 'Мой дикий друг', 2024, 'Комедия', NULL, 'Семиклассник Саша Меньшиков заканчивает учебный год в новой школе и живёт со своей тётей Ниной в маленьком живописном городке. Мама Саши, известный учёный, на время своей очередной экспедиции привезла его сюда из Москвы. С одноклассниками у Саши не заладилось, после школы он часто в одиночестве гуляет на природе. Однажды в лесу Саша находит маленького лисёнка, попавшего в капкан. Узнав, что за лисёнком охотятся браконьеры, мальчик прячет его в землянке в глубине леса и начинает выхаживать. С этого начинается трогательная и полная приключений история о дружбе, ответственности и справедливости.', 'https://image.tmdb.org/t/p/w500/ty7cvs6bCi8dJvy9Ofya26dcSgY.jpg', 5, '2026-07-15 14:32:01');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (175, 'Царевна-лягушка', 2025, 'Фантастика', 3, 'В пруду городского парка жила-была лягушка, которая очень любила смотреть фильмы в летнем кинотеатре. Однажды она увидела мультфильм, о том, как такая же, как она поймала стрелу и превратилась в прекрасную девушку. Пораженная событиями фильма, лягушка принимает все происходящее за действительность и отправляется на поиски стрелы. Но вместо нее ловит мячик для гольфа.', 'https://image.tmdb.org/t/p/w500/hkKIXuBmJUXiCyNI22Y4CY89Ntp.jpg', 5, '2026-07-15 14:32:01');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (176, 'Баба Яга спасает Новый год', 2024, 'Комедия', 3, 'Снежная королева и Дед Мороз были когда-то давними друзьями, вместе постигавшими магию холода. Но их пути разошлись, когда Снежная королева, позавидовав силе друга, похитила магический артефакт, из которого Дед Мороз черпал свою силу и творил волшебство. Волшебник не без труда смог победить колдунью и заточил ее в ледяную тюрьму. Спустя тысячи лет, в наши дни, мальчик Юра на новогодней ярмарке находит ледяной посох Снежной Королевы и невольно освобождает ее. Вернувшись в современный мир, она решает отомстить заклятому другу и придумывает коварный план, который заморозит весь мир в канун Нового года. Для этой цели она похищает мальчика и увозит его в ледяное королевство. Чтобы помешать ее козням и спасти не только Юру, но и весь мир, Деду Морозу понадобится помощью волшебницы Бабы Яги, Ивана Царевича, Марьи-искусницы и других магических существ.', 'https://image.tmdb.org/t/p/w500/huIhNSjhvDz3B9Qr28RqdTyScbp.jpg', 5, '2026-07-15 14:32:02');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (177, 'Психиатрическая больница Конджиама', NULL, 'Ужасы', NULL, NULL, NULL, 5, '2026-07-15 14:32:02');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (178, 'Яга на нашу голову', 2025, 'Комедия', 3, 'Дед Мороз решает отправить Ягу на перевоспитание к Пете, мальчику, у которого есть свои проблемы — он хочет помирить своих родителей до Нового года. Родители Пети уделяют больше времени работе, чем семье, и Петя стремится исправить эту ситуацию перед наступлением нового года.', 'https://image.tmdb.org/t/p/w500/gA2i8fH9WnL60cpCXsWByz7SRdi.jpg', 5, '2026-07-15 14:32:03');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (179, 'Алиса в стране чудес', 2025, 'Фантастика', 2, '15-летняя Алиса попадает в Страну Чудес, где солнце всегда в зените и нет времени. Среди жителей она узнаёт своих родных, знакомых и друзей, но никто из них не узнаёт Алису. Она для них чужая, антипят, а сами жители Страны Чудес называют себя антиподами. Чтобы вернуться домой, Алисе предстоит преодолеть множество препятствий и странностей.', 'https://image.tmdb.org/t/p/w500/7wQng3J0vvLBiWfSnjJzkuPnw7l.jpg', 5, '2026-07-15 14:32:03');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (180, 'Финист. Первый богатырь', 2024, 'Фантастика', 3, 'Финист Ясный Сокол — самый удалой богатырь Белогорья, самый сильный, самый ловкий и самый красивый. Все остальные богатыри на него равняются, дети хотят быть на него похожими, а девушки — просто заглядываются. Он горделив и самоуверен, и порой даже отказывается от подвигов, если считает их скучными и неинтересными. Но ему просто необходимо оставаться лучшим, чтобы люди продолжали им восхищаться. Чтобы всех удивить, Финист отправится за новыми свершениями в непростое путешествие, которое приведет его в восточные земли, где богатырь поймет простую истину — один в поле не воин.', 'https://image.tmdb.org/t/p/w500/pE4PE6gjxJvd9BLXVVNL4Ohjtmf.jpg', 5, '2026-07-15 14:32:04');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (181, 'Горыныч', 2025, 'Фантастика', 2, 'Лихой моряк Алексей Алехин узнает, что жизнь как в сказке — это настоящее приключение. Как только Леха вынырнул со дна морского в неопознанном княжестве, и едва успел спасти малыша-дракончика, оставшегося одного, начались проблемы: срочно излечить неизлечимую хандру князя Филимона, победить непобедимого силача Бамбулу, защитить княжество от коварных врагов и жадных предателей. И впервые в жизни встретить принцессу. Столько дел, что голова кругом идет! В опасных приключениях моряку помогает верный друг — маленький дракон Горыныч, который считает Леху родной мамой. Но друзей ждет огромный сюрприз…', 'https://image.tmdb.org/t/p/w500/7KKM9zoiNgm7q0cBEGtcpABI4Ai.jpg', 5, '2026-07-15 14:32:04');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (182, 'По стучись в мою Тверь', NULL, 'Комедия', NULL, NULL, NULL, 5, '2026-07-15 14:32:05');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (183, 'Равиоли Оли', 2026, 'Мультфильм', 3, 'Ольга Бузова, звезда сцены и экрана, мечтает о романтическом будущем с идеальным мужчиной — красавцем-немцем Генрихом, который вот-вот сделает ей предложение. Она планирует купить квартиру на заработанные деньги, но Генрих предлагает ей рискнуть и вложить средства в его бизнес — завод по производству пельменей в Нижних Теплышках. Влюблённая и полная надежд Оля соглашается, но вскоре узнает, что возлюбленный оказался аферистом и исчез с её деньгами. Не желая сдаваться, Бузова решает отправиться в маленький город, чтобы распродать оборудование завода и вернуть хотя бы часть средств.', 'https://image.tmdb.org/t/p/w500/lqn4mt8VQd5eT2avljgz7ddr3Xn.jpg', 5, '2026-07-15 14:32:05');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (184, 'Несвятая Валентина', 2026, 'Комедия', NULL, 'Девушка, которой не везет в личной жизни, приобретает аллергию на любовь. Она чихает на влюбленных, и они расстаются. Это ставит под угрозу ее карьеру, любовь родителей и близкой подруги. Поэтому ей срочно нужно «вылечиться».', 'https://image.tmdb.org/t/p/w500/r3VYKTTjnx9ldVScsccBZY6Jc6S.jpg', 5, '2026-07-15 14:32:06');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (185, 'Поступь хаоса', 2021, 'Ужасы', 3, '2257 год. Родина Тодда Хьюитта — колонизированная планета Новый Мир, где мысли мужчин имеют визуально-звуковое воплощение и называются шумом. Парень живёт в небольшой деревне, населённой исключительно мужчинами, и ещё не научился скрывать свои мысли от окружающих. Однажды над планетой терпит крушение корабль-разведчик из второй волны колонистов, в результате чего Тодд впервые в сознательной жизни видит девушку. Местный мэр решет использовать её в своих коварных планах, но девушка сбегает, и теперь без помощи Тодда ей не обойтись.', 'https://image.tmdb.org/t/p/w500/nKik625zZGwj7zniLH3uTgIeekC.jpg', 5, '2026-07-15 14:32:06');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (186, 'Вышка', 2022, 'Ужасы', 4, 'После гибели Дэна в результате падения со скалы его жена Бекки, ранее увлекавшаяся экстремальными развлечениями, впала в депрессию. Год спустя девушка всё ещё не может прийти в себя и регулярно заливает горе алкоголем, когда в её жизни внезапно появляется старая боевая подруга Хантер. Та предлагает почтить память Дэна, забравшись на телерадиомачту B67 и развеяв там его прах. Девушки отправляются к самому высокому сооружению Соединённых Штатов, даже не представляя, с чем им придётся столкнуться на его верхушке.', 'https://image.tmdb.org/t/p/w500/8xukbVG9JJfnpcdIEYPijVVOfhH.jpg', 5, '2026-07-15 14:32:07');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (187, 'Прыжок в будущее', 2023, 'Фантастика', 4, 'Тео и Оскар — два брата. Однажды их мама, изучающая перемещение во времени, бесследно исчезает. Братьям придется отправиться на поиски матери, самим отыскать портал и пуститься в удивительное путешествие, совершая прыжки во времени.', 'https://image.tmdb.org/t/p/w500/3GVC2V5o8uqI1hl96WUT3bvBg6O.jpg', 5, '2026-07-15 14:32:07');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (188, 'Сказка о царе Салтане', 2026, 'Мультфильм', 3, 'Остановившийся на постой в деревенском доме царь Салтан влюбляется в милую, добрую и простую девушку Аннушку. Аннушка выходит замуж за царя и рожает ему сына. Её сестрам и мачехе посчастливилось словно по мановению волшебной палочки вслед за Аннушкой оказаться в царском дворце. Но сёстры и мачеха не ценят своего счастья, желают большего и закручивают интригу. Пока Салтан находится в отъезде, они подменяют письмо и выставляют в дурном свете перед царём Аннушку и новорождённого наследника. Салтан в бешенстве, но велит ждать своего возвращения, однако письмо с приказом снова подменяют. В результате царицу с сыном запечатывают в бочку и бросают в океан на верную погибель.', 'https://image.tmdb.org/t/p/w500/7i1aQ0dkmJSxpBOqPFGEel5NB9Z.jpg', 5, '2026-07-15 14:32:08');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (189, 'Как не жениться на принцессе', 2021, 'Мультфильм', 3, 'В замок прибывают три предсказательницы. Они пророчат Маленькому принцу Леопольду брак с дочерью соседнего короля — принцессой Жозефиной. Однако Леопольд и Жозефина с детства друг друга ненавидят, хотя их родители настаивают на свадьбе ради исполнения пророчества. В день церемонии молодые похищают волшебные часы предсказательниц и переносятся в прошлое, чтобы помешать судьям вмешиваться в жизни людей. Им удаётся изменить ход событий, но, вернувшись в настоящее, они обнаруживают, что изменения затронули не только их судьбы, но и весь облик королевства.', 'https://image.tmdb.org/t/p/w500/d5YEXrZpeyq9uRvysBQR2D33EN4.jpg', 5, '2026-07-15 14:32:08');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (190, 'Первая', 2026, 'Драма', 1, 'У Паши никогда не было любви, но есть ночной клуб, доставшийся в наследство. У клуба долги. Паша не справляется, но и продать не может — это всё, что осталось от родителей. А еще у Паши есть подруга Леся, которая терпеливо ждёт, когда его чувства наконец-то оттают. И они размораживаются, когда Леся знакомит Пашу со своей подругой Алисой. Алиса не в ответе за тех, кого приручила. Она и станет первой, кто взломает чувства Паши, превратив его жизнь в полное безумие.', 'https://image.tmdb.org/t/p/w500/ohHWp29GvkBC7aepF2fhP8LHF8o.jpg', 5, '2026-07-15 14:32:09');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (191, 'Смерть единорога', 2025, 'Ужасы', 3, 'Ридли вынуждена провести выходные с отцом-трудоголиком Эллиотом. И когда кажется, что их отношения может спасти только чудо, они сбивают… настоящего единорога. Алчная семейка, на которую работает Эллиот, тут же решает монетизировать его целебные свойства. Но настоящее волшебство начинается с появлением родителей детёныша, ведь свирепые единороги открывают охоту на жадных богачей — и теперь каждый получит по рогам.', 'https://image.tmdb.org/t/p/w500/lVINt3dHhoMBLscMog0oYzrjCzR.jpg', 5, '2026-07-15 14:32:09');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (192, 'Еретик', 2024, 'Ужасы', 3, 'Церковная миссия приводит двух девушек к дверям обманчиво безобидного мистера Рида. Не успев опомниться, они оказываются в его дьявольской ловушке, построенной с целью проверить их веру на прочность. Чтобы выжить, им придется пройти серию изощренных испытаний и столкнуться с тем, что не поддается рациональному объяснению. Теперь выбор, во что верить, для них означает выбор между жизнью и смертью.', 'https://image.tmdb.org/t/p/w500/4lkzFgDXdTXHWeiO0WtY9VIK2FV.jpg', 5, '2026-07-15 14:32:10');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (193, 'Коты-эрмитажа', 2023, 'Мультфильм', 3, 'Юный кот по имени Винсент в компании мыши Мориса спасается от наводнения в старинном клавесине, который подбирают моряки и отправляют в Санкт-Петербург, где он попадает в Эрмитаж. Там Винсент знакомится с элитным кошачьим отрядом, что столетиями охраняет произведения искусства от мышей и прочих вредителей. Винсент мечтает обрести настоящую кошачью семью, но не хочет терять и своего друга Мориса, спасшего ему жизнь. Винсенту приходится скрывать друга, у которого к тому же есть одна «маленькая слабость» – Морис обожает грызть шедевры живописи. Ситуация максимально усложняется, когда в Эрмитаж прибывает одна из величайших картин человечества – «Мона Лиза», сгрызть которую – мечта всех мышей. Но ни Винсент, ни Морис, ни коты Эрмитажа не подозревают, что картину собираются похитить. И теперь Винсенту придется проявить всю свою изворотливость и смелость, чтобы спасти шедевр, защитить честь музея и завоевать любовь кошки по имени Клеопатра из египетского зала...', 'https://image.tmdb.org/t/p/w500/nPDzti70yXK1cFfnKwDYUlmYAN6.jpg', 5, '2026-07-15 14:32:10');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (194, 'Золушка. Тайна трёх желаний', 2026, 'Мультфильм', 3, 'Молодая девушка Золушка живёт со строгой мачехой, но не переживает из-за трудностей – её поддерживает верный друг Северин, простой дровосек. Северин мечтает стать знаменитым, но однажды попадает под действие заклятия: он находит волшебное дерево, которое превращает его в бурундука. Чтобы вернуть парню его обычный облик, Золушке предстоит проявить доброту и храбрость, а также попасть на королевский бал вопреки протестам мачехи.', 'https://image.tmdb.org/t/p/w500/daUeNwYAc9SRRLiC6bFeoOWV3MU.jpg', 5, '2026-07-15 14:32:11');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (195, 'Холоп', 2019, 'Комедия', 3, 'Эгоистичный «мажор» Гриша в один не очень прекрасный день после аварии приходит в себя... в 1860 году в барской усадьбе. Теперь он — обычный холоп без связей и связи: о смартфонах здесь не слышали, а все вокруг него — крепостные. Грише предстоит пройти непростой путь, чтобы из наглого сынка богатых родителей превратиться в человека, который умеет ценить простые вещи, умеет дружить, ну и, конечно, любить.', 'https://image.tmdb.org/t/p/w500/f78tgHLtWeVLl4JPygiIbCS8yE2.jpg', 5, '2026-07-15 14:32:11');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (196, 'Тайна Коко', 2017, 'Мультфильм', 4, '12-летний Мигель живёт в мексиканской деревушке в семье сапожников и тайно мечтает стать музыкантом. Тайно, потому что в его семье музыка считается проклятием. Когда-то его прапрадед оставил жену, прапрабабку Мигеля, ради мечты, которая теперь не даёт спокойно жить и его праправнуку. С тех пор музыкальная тема в семье стала табу. Мигель обнаруживает, что между ним и его любимым певцом Эрнесто де ла Крусом, ныне покойным, существует некая связь. Паренёк отправляется к своему кумиру в Страну Мёртвых, где встречает души предков. Мигель знакомится там с духом-скелетом по имени Гектор, который становится его проводником. Вдвоём они отправляются на поиски де ла Круса.', 'https://image.tmdb.org/t/p/w500/jvYsGaUqN8ymH696kRfVJjJ3GIl.jpg', 5, '2026-07-15 14:32:12');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (197, 'Дюна', 2021, 'Фантастика', 4, 'Наследник знаменитого дома Атрейдесов Пол отправляется вместе с семьей на одну из самых опасных планет во Вселенной — Арракис. Здесь нет ничего, кроме песка, палящего солнца, гигантских чудовищ и основной причины межгалактических конфликтов — невероятно ценного ресурса, который называется меланж. В результате захвата власти Пол вынужден бежать и скрываться, и это становится началом его эпического путешествия. Враждебный мир Арракиса приготовил для него множество тяжелых испытаний, но только тот, кто готов взглянуть в глаза своему страху, достоин стать избранным.', 'https://image.tmdb.org/t/p/w500/3hbXNclcHaj5KiF6kK41GBMjyFr.jpg', 5, '2026-07-15 14:32:12');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (198, 'Дом монстр', 2006, 'Мультфильм', 3, 'Хорошо быть мальчишкой. Каждый день, как вся жизнь! Столько всего вокруг: девчонки, мороженое, драки, учебники, футбол. Насыщенный день, короче, получается. А вот если ты однажды обнаружил, что дом, который стоит по соседству с домом твоей семьи — вовсе не дом… А попросту говоря — монстр. Чудовище, в общем. Такие дела.Ну вот, история эта про то, как три приятеля — ДиДжей, Чёдер и Дженни — обнаружили, что дом, находящийся неподалеку, самый настоящий монстр. Только никто им не верил. Мало ли, чего навыдумывают дети… Только зря они так. Ребята их предупреждали…При создании фильма использовалась технология технологии motion capture. Актеры, одетые в костюмы, снимались вживую, а затем их движения оцифровывались и переносились на 3D-модели персонажей. На съемки ушло 42 дня. Для записи стонов и скрипов, которые издавал дом-монстр, не был задействован ни один синтезатор. Был найден очень старый сарай и были записаны звуки, которые издавала эта развалюха.', 'https://image.tmdb.org/t/p/w500/pMc6kgawZybpnHuvPsrbgLWIGCW.jpg', 5, '2026-07-15 14:32:13');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (199, 'Аватар 2', 2022, 'Фантастика', 4, 'Джейк становится предводителем народа на’ви и берёт на себя миссию по защите новых друзей от корыстных бизнесменов с Земли. Теперь ему есть за кого бороться - с Джейком его прекрасная возлюбленная Нейтири. Когда на Пандору возвращаются до зубов вооружённые земляне, Джейк готов дать им отпор.', 'https://image.tmdb.org/t/p/w500/yFNn7uWudLLWDJqfj3fwh5CcUdR.jpg', 5, '2026-07-15 14:32:13');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (200, 'Субстанция', 2024, 'Ужасы', 4, 'Слава голливудской звезды Элизабет Спаркл осталась в прошлом, хотя она всё ещё ведёт фитнес-шоу на телевидении. Когда её передачу собираются перезапустить с ведущей помоложе, от отчаяния Элизабет решает принять инновационный препарат, создатели которого обещают невероятное преображение, но при соблюдении правила одной недели. Так на свет появляется молодая красотка Сью. Девушка начинает делать карьеру в шоу-бизнесе и вскоре решает, что семи дней ей маловато.', 'https://image.tmdb.org/t/p/w500/x3yhBGbTqlAjxM450BANUNCHpOO.jpg', 5, '2026-07-15 14:32:14');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (201, 'Тепло наших тел', 2013, 'Триллер', 3, 'Мир поражен чумой и стоит на грани вымирания. Покойники ходят по земле и норовят употребить в пищу живых, которые, оставшись в катастрофическом меньшинстве, с трудом держат оборону. Перемены начинаются, когда один зомби, чье имя при жизни начиналось на «Р», спасает девушку вместо того, чтобы ее съесть. Дружба, завязавшаяся между представителями враждующих сторон, грозит обоим самыми нехорошими последствиями. Но Р и Джули, сами того не подозревая, держат в руках простой и единственный ключ к спасению гибнущего мира.', 'https://image.tmdb.org/t/p/w500/t9Y49pYbXBAv2jQQQGpzKGZZt6Q.jpg', 5, '2026-07-15 14:32:14');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (202, 'Мавка', 2023, 'Мультфильм', 4, 'Древний волшебный Лес никогда не пускал людей в свои таинственные глубины. Люди из соседнего села и сами держались от него подальше - думали, что Лес опасен, потому что в нём обитают загадочные лесные существа. И вдруг произошло чудо. Мавка - одна из тех самых лесных созданий, душа Леса и его будущая царица, - и Лукаш, простой деревенский кузнец, полюбили друг друга больше всего на свете. Но их миры пошли войной друг на друга. А всё из-за появления в селе коварной фабрикантши Килины, которая построила рядом с лесом фабрику, задумав уничтожить Лес. Смогут ли Мавка и Лукаш остановить войну между людьми и Лесом? Помешают ли они Килине покорить природу? Спасут ли собственную любовь?', 'https://image.tmdb.org/t/p/w500/mjVNDAYjHW93FWTR8BJAffTszeK.jpg', 5, '2026-07-15 14:32:15');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (203, 'Волшебник изумрудного города', 1994, 'Фантастика', 3, 'Фильм рассказывает о необыкновенных приключениях девочки Элли и ее друзей в волшебной стране.', 'https://image.tmdb.org/t/p/w500/tEJFD53qavxRm9GPHllCgGoKMrV.jpg', 1, '2026-07-15 14:32:15');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (204, 'Птичий короб', 2018, 'Ужасы', 3, 'Пять лет назад мир погрузился в хаос: увидев нечто, люди кончают жизнь самоубийством. Женщина с двумя пятилетними детьми, услышав по радио о безопасном месте, отправляется на поиски выжившей общины и прихватывает с собой попугаев в коробке. Чтобы сохранить жизнь в этом новом мире, самое главное — не смотреть по сторонам и слушать, как птицы реагируют на приближающуюся опасность.', 'https://image.tmdb.org/t/p/w500/dWbhNl7ESABUqXfyOKPr5EQaDXP.jpg', 5, '2026-07-15 14:32:16');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (205, 'Гладиатор', 2000, 'Боевик', 4, 'Римская империя. Бесстрашного и благородного генерала Максимуса боготворят солдаты, а старый император Марк Аврелий безгранично доверяет ему и относится как к сыну. Однако опытный воин, готовый сразиться с любым противником в честном бою, оказывается бессильным перед коварными придворными интригами. Коммод, сын Марка Аврелия, убивает отца, который планировал сделать преемником не его, а Максимуса, и захватывает власть. Решив избавиться от опасного соперника, который к тому же отказывается присягнуть ему на верность, Коммод отдаёт приказ убить Максимуса и всю его семью. Чудом выжив, но не сумев спасти близких, Максимус попадает в плен к работорговцу, который продаёт его организатору гладиаторских боёв Проксимо. Так легендарный полководец становится гладиатором. Но вскоре ему представится шанс встретиться со своим смертельным врагом лицом к лицу.', 'https://image.tmdb.org/t/p/w500/1wjNqlfsuHNTXTpCt2ZOV2iPxaf.jpg', 5, '2026-07-15 14:32:16');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (206, 'Заклятие', 2013, 'Ужасы', 4, 'Эд и Лоррейн Уоррены — детективы, которые расследуют паранормальные дела. Однажды к ним обращается семья, страдающая от злого духа. Уоррены, вынужденные сражаться с могущественной демонической сущностью, сталкиваются с самым пугающим случаем в своей жизни.', 'https://image.tmdb.org/t/p/w500/dq99MpZPTpHOFaZCGvYz3o2uwQk.jpg', 5, '2026-07-15 14:32:17');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (207, 'Король лев', 1994, 'Мультфильм', 4, 'У величественного Короля-Льва Муфасы рождается наследник по имени Симба. Уже в детстве любознательный малыш становится жертвой интриг своего завистливого дяди Шрама, мечтающего о власти. Симба познаёт горе утраты, предательство и изгнание, но в конце концов обретает верных друзей и находит любимую. Закалённый испытаниями, он в нелёгкой борьбе отвоёвывает своё законное место в «Круге жизни», осознав, что значит быть настоящим Королём.', 'https://image.tmdb.org/t/p/w500/j8tdiuhbF9p5mnAeA1YOUvz82xY.jpg', 5, '2026-07-15 14:32:17');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (208, 'Шрек', 2001, 'Мультфильм', 4, 'Присоединяйтесь к Шреку и его друзьям из Далекого-далекого Королевства, которые поделятся историями о праздничном настроении, жуткими сказками, музыкальным состязанием и незабываемой ночью присмотра за детьми.', 'https://image.tmdb.org/t/p/w500/5OPCH713UIEeWuvRZpVkkzrZ3Hd.jpg', 5, '2026-07-15 14:32:18');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (209, 'Корпорация монстров', 2001, 'Мультфильм', 4, 'Склизкий гад в сливном бачке, мохнатый зверь, похожий на чудовище из «Аленького цветочка», гигантские мокрицы под кроватью — все они существуют на самом деле. Все, что им нужно — пугать детей, потому что из детских криков они получают электричество. Полнометражный мультфильм рассказывает о кризисах в мире монстров, их жизни. Но однажды вся мирная жизнь монстров оказывается под угрозой: в их мир попадает ребенок. А с детьми столько хлопот, что они могут довести даже монстров.', 'https://image.tmdb.org/t/p/w500/zXIusESsQ7ZXP9MFwbvcTTZ3XWF.jpg', 5, '2026-07-15 14:32:18');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (210, 'Из тьмы', 2024, 'Ужасы', 3, 'События происходят в каменном веке и рассказывают историю группы разрозненных древних людей, которые объединяются, чтобы найти новую землю. В поисках лучшей жизни, обещанной их лидером, племя рискует всем и отправляется в опасное путешествие по неизведанным и опасным землям. Но когда они подозревают, что за ними охотится злобная, потенциально мистическая сущность, напуганное племя вынуждено противостоять опасности, о существовании которой они даже не подозревали.', 'https://image.tmdb.org/t/p/w500/Yj89ajPfJ6TJgHmUsKfkPlEztM.jpg', 5, '2026-07-15 14:32:19');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (211, 'Рататуй', 2007, 'Мультфильм', 4, 'Париж! Рай для гурмана — лучшая еда, лучшие рестораны, лучшие повара! Реми мечтает стать одним из них — величайшим поваром столицы мировой кулинарии. У Реми есть для этого все — идеальный нюх и вкус, знание лучших рецептов и невероятные способности к импровизации. Есть только одна проблема... Реми — крыса. Родственники Реми, корят его за предательство традиций крысиного племени, а хозяин ресторана — повар по имени Живодэр — старается извести. Только поваренок Лингвини, который подружился с Реми, разделяет его склонность к несбыточным мечтам.', 'https://image.tmdb.org/t/p/w500/6u4JvZBiw1Uv6BgTlWNsFSSHlMn.jpg', 5, '2026-07-15 14:32:19');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (212, 'Хранитель Луны', 2015, 'Фантастика', 4, 'На диковинной планете, где смена дня и ночи осуществляется вручную, юного фавна Мьюна неожиданно избирают хранителем Луны. Но к своему ужасу, он почти сразу теряет ее! Воспользовавшись этим, царь подземного мира Некрос крадет и гасит Солнце. Теперь, чтобы спасти планету, Мьюн вместе с отважной девочкой из воска Глим и заносчивым Сохоном, хранителем Солнца, должны отправиться в удивительное и опасное путешествие.', 'https://image.tmdb.org/t/p/w500/yCEBDLJrRDiB5yCEarmRI75xkYM.jpg', 5, '2026-07-15 14:32:20');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (213, 'Дорога домой', 2021, 'Семейный', 4, 'Весна 1944 года. Польша. Партизанский отряд, сформированный из советских военнопленных, бежавших из концлагеря, пробивается на Родину...', 'https://image.tmdb.org/t/p/w500/nkXZwR8k46VDdjdcOctVgZC3MJ5.jpg', 5, '2026-07-15 14:32:20');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (214, 'Монстры на каникулах', 2012, 'Мультфильм', 3, 'Граф Дракула для себя и своей любимой дочки построил хорошо укрытый от посторонних глаз отель, куда монстры со всего света приезжают отдохнуть от семейных забот, повседневной суеты и, конечно… людей. Но вездесущие американские туристы проникают и сюда.', 'https://image.tmdb.org/t/p/w500/udgsh0Gh7KAEBWSjI4MC2Aq28rG.jpg', 5, '2026-07-15 14:32:21');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (215, 'Босс молокосос', 2017, 'Мультфильм', 3, 'Существует множество пособий, рекомендаций, советов по воспитанию детей. Но вот что делать, если ребенок родился с задатками самого въедливого начальника и видит вокруг себя только подчиненных — ленивых, безалаберных и бездарных?', 'https://image.tmdb.org/t/p/w500/3kD6yrPx59TRvYXSCZgAB23CzQK.jpg', 5, '2026-07-15 14:32:21');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (216, 'Дикий робот', 2024, 'Мультфильм', 4, 'После кораблекрушения, умный робот по имени Роз оказывается на необитаемом острове. Чтобы выжить в суровых условиях, Роз налаживает связь с животными острова и заботится об одиноком гусенке-сироте.', 'https://image.tmdb.org/t/p/w500/sDTumQBxhIyYbZ9acsTtoLfb5ZG.jpg', 5, '2026-07-15 14:32:22');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (217, 'Орион и тьма', 2024, 'Мультфильм', 3, 'Мальчик с богатым воображением смотрит страхам в глаза во время незабываемого ночного путешествия с новым другом — улыбчивым гигантом по имени Тьма.', 'https://image.tmdb.org/t/p/w500/1JAieHqVS6oulLGCqjKqwRSftwo.jpg', 5, '2026-07-15 14:32:22');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (218, 'Энканто', 2021, 'Мультфильм', 4, 'Удивительная семья Мадригалов живёт в спрятанном в горах Колумбии волшебном доме, расположенном в чудесном и очаровательном уголке под названием Энканто. Каждого ребёнка в семье Мадригалов магия этого места благословила уникальным даром — от суперсилы до способности исцелять. Увы, магия обошла стороной одну лишь юную Мирабель. Обнаружив, что магия Энканто находится в опасности, Мирабель решает, что именно она может быть последней надеждой на спасение своей особенной семьи.', 'https://image.tmdb.org/t/p/w500/yAw00ke7CzSLe4mMuCGkAzma69K.jpg', 5, '2026-07-15 14:32:23');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (219, 'Бэмби', 1942, 'Мультфильм', 3, 'Направляясь в гости к бабушке, Ксана и семилетний Бенджи попадают в страшную автокатастрофу в лесу. Виной аварии становится мутировавший олень — Бэмби — идущий по кровавому следу, чтобы отомстить людям за смерть матери. С этого момента начинается смертельная игра на выживание.', 'https://image.tmdb.org/t/p/w500/4I6TyE33M6vcBFxrNMWNuXl1Aya.jpg', 5, '2026-07-15 14:32:23');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (220, 'Мулан', 1998, 'Мультфильм', 4, 'Для великого народа наступили тяжелые времена: на страну напало воинственное племя гуннов. Переодевшись в мужскую одежду, Мулан присоединяется к другим воинам и отправляется в опасный поход к подножию заснеженных гор. Ее сопровождает забавный дракончик Мушу, который больше похож на маленькую собачку, чем на мифическое чудовище.Пытаясь скрыть тайну, они попадают в забавные ситуации и не подозревают, что их секрет вот — вот раскроется!…', 'https://image.tmdb.org/t/p/w500/wLB0VhC2FafMr6QEVH9ReX0Id3j.jpg', 5, '2026-07-15 14:32:24');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (221, 'Белоснежка', 2025, 'Мультфильм', 2, 'После исчезновения доброго короля в военном походе, его юная дочь Белоснежка становится круглой сиротой и невольно начинает прислуживать злой мачехе с магическими способностями, захватившей власть в королевстве. По мере взросления принцесса затмевает своей красотой тщеславную королеву, чем навлекает на себя смертельную опасность. После покушения на свою жизнь Белоснежка вынуждена укрыться в причудливом каменном домике в дремучем лесу, где её друзьями становятся 7 разнохарактерных гномов и благородный разбойник Джонатан.', 'https://image.tmdb.org/t/p/w500/aOpByJVRjjKncEYIOQZD3CcpYdE.jpg', 5, '2026-07-15 14:32:24');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (222, 'Красавица и Чудовище', 2017, 'Мультфильм', 3, 'Обозлённая Волшебница превратила принца Адама в отвратительное чудовище за то, что тот был злым, самовлюблённым и грубым. Чтобы снять чары с себя и слуг своего замка, ему необходимо научиться быть добрым, любить и быть любимым. Произойти это должно до того, как с розы, подаренной Волшебницей, упадёт последний лепесток.  В далёкой деревушке живёт красивая девушка по имени Белль. Однажды её отец Морис отправляется на ярмарку, но по дороге сбивается с пути. Оказавшись в заколдованном замке, он становится пленником Чудовища. Белль спешит отцу на помощь.', 'https://image.tmdb.org/t/p/w500/bETMkjKVKXgXn591UZ9pFqAKQ6z.jpg', 5, '2026-07-15 14:32:25');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (223, 'Спящая красавица', 1959, 'Мультфильм', 3, 'Давным-давно в далекой стране жили король с королевой. Когда у них родилась долгожданная дочь Аврора, в королевстве был устроен большой праздник, чтобы все могли поприветствовать малютку. На бал пригласили и трех добрых фей — Флору, Фауну и Хорошую Погоду, а про злую колдунью Мэлифисент забыли.  Оскорбленная, она наложила на принцессу проклятье — в день своего 16-летия Аврора уколется о веретено и уснет вечным сном. Колдовство оказалось таким сильным, что добрые феи не смогли разрушить его. Но все же они спасли принцессу: она очнется ото сна после поцелуя прекрасного принца…', 'https://image.tmdb.org/t/p/w500/9WQPTlptMe9RPefcoXt0KsZeh3f.jpg', 5, '2026-07-15 14:32:25');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (224, 'Алладин', 2019, 'Приключения', 4, 'Молодой воришка по имени Аладдин хочет стать принцем, чтобы жениться на принцессе Жасмин. Тем временем визирь Аграбы Джафар, намеревается захватить власть над Аграбой, а для этого он стремится заполучить волшебную лампу, хранящуюся в пещере чудес, доступ к которой разрешен лишь тому, кого называют "алмаз неограненный", и этим человеком является никто иной как сам Аладдин.', 'https://image.tmdb.org/t/p/w500/t7D1Q4qQ4LjlaUXUqB7ny3xdIAy.jpg', 5, '2026-07-15 14:32:26');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (225, 'Анабель', 2015, 'Ужасы', 3, 'Три подруги, Анабель, Сандра и Крис, совместно снимают квартиру. Неожиданно Анабель исчезает, не оставляя ни следа своего присутствия. Оставшиеся вынуждены искать нового компаньона. По объявлению приходит пожилой обходительный господин по имени Лусио. Не видя от него никакой опасности, девушки соглашаются отдать ему пустующую комнату. Но с появлением в квартире нового жильца, в ней начинают происходить странные и непонятные события…', 'https://image.tmdb.org/t/p/w500/iWjPWr8USnYM8M9twN9C11kI1cB.jpg', 5, '2026-07-15 14:32:26');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (226, 'Париж горит мёртвых', 1966, 'Военный', 4, 'Гитлер издаёт чудовищный приказ о минировании Парижа и поручает генералу фон Хольтицу стереть город с лица земли. Генерал Леклерк, возглавляющий бронетанковую дивизию, а также французское сопротивление во главе с будущим премьер-министром Франции — Шабан-Дельмасом — должны сделать всё, чтобы спасти родной город от уничтожения.', 'https://image.tmdb.org/t/p/w500/rp26Y9vTWzicqmsy9FvNaRSXgwN.jpg', 5, '2026-07-15 14:32:27');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (227, 'Оно', 2017, 'Боевик', 3, 'В основе сюжета - история уездного города Глупова от начала века до возможного будущего...', 'https://image.tmdb.org/t/p/w500/kBsrHzObDPfqnzPNFSRoMbGdJnb.jpg', 5, '2026-07-15 14:32:27');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (228, 'Фирстрит', NULL, 'Драма', NULL, NULL, NULL, 5, '2026-07-15 14:32:28');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (229, 'Монстры в Париже', 2011, 'Приключения', 3, 'Париж. 1910 год. Ужасный монстр, напоминающий гигантское насекомое, нагоняет страх на всю Францию. Застенчивый киномеханик и неутомимый изобретатель начинают охоту на него. В этой погоне они знакомятся со звездой кабаре, сумасшедшим ученым и его умной обезьянкой и, наконец, самим монстром, который оказывается совсем не страшным. Теперь безобидное, как блоха, чудовище ищет у своих новых друзей защиты от вредного начальника городской полиции.', 'https://image.tmdb.org/t/p/w500/u0usGgh9iKt1hjGE9frlBPlNguv.jpg', 5, '2026-07-15 14:32:28');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (230, 'В поисках Немо', 2003, 'Мультфильм', 4, 'Рыба-клоун Марлин живёт на Большом Барьерном рифе и после трагедии становится чрезмерно осторожным отцом. Когда его единственного сына Немо ловят люди и увозят далеко от дома, Марлин отправляется через весь океан на его поиски. По пути он встречает добродушную и забывчивую рыбку Дори, которая становится его спутницей в полном опасностей путешествии. Им предстоит столкнуться с акулами, медузами, морскими течениями и множеством других испытаний. Тем временем Немо, оказавшись в аквариуме стоматологической клиники, пытается найти способ вернуться к отцу и не теряет надежды на спасение.', 'https://image.tmdb.org/t/p/w500/wwUYKw29xtFLk5PIZV9iDAs6zlW.jpg', 5, '2026-07-15 14:32:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (231, 'Смурфики', 2011, 'Мультфильм', 3, 'Спасаясь от злого волшебника Гаргамеля, крошечные смурфики оказываются за пределами родной деревни. Из своего волшебного мира они попадают прямиком в наш мир, а именно в Центральный парк города Нью-Йорк. Теперь маленьким отважным смурфикам предстоит отыскать дорогу домой и не попасть в лапы Гаргамеля.', 'https://image.tmdb.org/t/p/w500/2Fqo8sDLfNYv8ofqAXCo8AZYoSo.jpg', 5, '2026-07-15 14:32:29');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (232, 'Девочки Эквестрии', 2013, 'Мультфильм', 4, 'Следуя за похитившим корону Кристальной Империи вором, Твайлайт Cпаркл попадает в альтернативный мир, в котором она превращается в девочку-подростка и сталкивается с самым серьёзным испытанием в своей жизни — старшей школой! При помощи своих новых друзей, которые напоминают ей оставшихся в Понивилле Эпплджек, Рэрити, Рэйнбоу Дэш, Пинки Пай и Флаттершай, она начинает поиски пропавшей короны. Поиски, которые изменят судьбы обоих параллельных миров.', 'https://image.tmdb.org/t/p/w500/3tQM3PUDn9i2iq0HP7yLlQsQ0ya.jpg', 5, '2026-07-15 14:32:30');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (233, 'Тень и кость', NULL, 'Фантастика', 4, 'В мире, разделенном на две части массивным барьером вечной темноты, где неестественные существа питаются человеческой плотью, молодой солдат раскрывает силу, которая может, наконец, объединить ее страну. Но, когда она борется за свою власть, против нее строят заговоры опасные силы. Бандиты, воры, убийцы и святые сейчас в состоянии войны, и для выживания потребуется больше, чем магия.', 'https://image.tmdb.org/t/p/w500/zMxOK6oRAPATW6vWzvkVfqcq98x.jpg', 1, '2026-07-15 14:32:30');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (234, 'Я хочу съесть твою поджелудочную', 2018, 'Аниме', 4, 'Ученик старших классов узнает, что у его одноклассницы серьезное заболевание поджелудочной железы. Он старается проводить с девушкой больше времени, и ребята становятся очень близки.', 'https://image.tmdb.org/t/p/w500/avj8X4mamOl9Co9rARHwivaP2Td.jpg', 5, '2026-07-15 14:32:31');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (235, 'Корзинка фруктов', 2022, 'Аниме', 4, 'Старшеклассница Кёко — трудный подросток: она прогуливает занятия, состоит в банде байкеров и постоянно ссорится с родителями, которые её не понимают. Всё изменилось, когда она встретила учителя Кацую Хонду, который проявил интерес к её, на первый взгляд, буйному нраву. Однако суть в том, что только он видит, как на самом деле страдает девушка. Чуткое и заботливое отношение Кацуи помогло наконец Кёко принять ошибки прошлого и начать новую жизнь, обрести желанные счастье и любовь. Но жизнь бывает жестока, и кто знает, что может произойти в самые счастливые её моменты.', 'https://image.tmdb.org/t/p/w500/kZfUFoTokW9GnouVHgfLoJkVlLQ.jpg', 5, '2026-07-15 14:32:31');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (236, 'Дитя погоды', 2019, 'Аниме', 4, '16-летний Ходака Морисима убегает из дома в Токио, где у него сразу кончаются деньги. Мало того, что без документов он не может найти работу, так ещё на улице идёт бесконечный дождь, и небо постоянно затянуто тучами. В отчаянии парень обращается к бывшему попутчику, а тот не только берёт его в свой журнал, пишущий о сверхъестественном, но и предоставляет жильё. Однажды Ходака знакомится с девушкой по имени Хина Амано, которая обладает удивительной способностью разгонять тучи и останавливать дождь.', 'https://image.tmdb.org/t/p/w500/koEIzx6yaqrLkmmScO68s5oDAyc.jpg', 5, '2026-07-15 14:32:32');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (237, 'В лес, где мерцают светлячки', 2011, 'Аниме', 4, 'Маленькая девочка Хотару заблудилась в заколдованном лесу, населенном привидениями. Она встречает мальчика в маске по имени Гин, но считает его лесным духом, который может растаять от одного прикосновения. С помощью нового друга Хотару выбралась из леса, но она не может забыть Гина.', 'https://image.tmdb.org/t/p/w500/pWSgfHJMLG5ce95HztUFqRYuX3D.jpg', 5, '2026-07-15 14:32:32');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (238, 'Тонешь в лето, выход прощаний', NULL, 'Аниме', NULL, NULL, NULL, 5, '2026-07-15 14:32:33');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (239, 'Сад изящных слов', 2013, 'Аниме', 4, 'Юноша по имени Такао встречает таинственную молодую женщину. Их случайные и как будто ни к чему не ведущие встречи в парке, где Такао прогуливает занятия, работая над достижением своей странной мечты — посвятить жизнь конструированию и изготовлению обуви — повторяются снова и снова, правда, только в ненастные дни. Сердца молодых людей начинают приоткрываться друг другу, но на это нужно время, а впереди уже маячит конец сезона дождей.', 'https://image.tmdb.org/t/p/w500/mwTqhLpm3TISNm5FJL58b7NHq8b.jpg', 5, '2026-07-15 14:32:33');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (240, 'Сердцу хочется кричать', NULL, 'Аниме', NULL, NULL, NULL, 5, '2026-07-15 14:32:34');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (241, 'Оседлав волну с тобой', NULL, 'Аниме', NULL, NULL, NULL, 5, '2026-07-15 14:32:34');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (242, 'Пять сантиметров в секунду', 2025, 'Драма', 4, 'Весна 1991 года: в токийской школе Такэки и Акари встречаются и словно нежно протягивая руки навстречу одиночеству друг друга, постепенно сближают свои сердца, но переезд разлучает их сразу после выпуска. Зимой в метель, под единственной сакурой, стоящей в снегу в Ивафуне, они дают обещание встретиться 26 марта 2009 года, и 18 лет спустя, в 2008-м, каждый, живя замкнутой жизнью в Токио, ощущают зов не угасающих воспоминаний и предчувствие судьбоносной встречи. Это тихая история о времени, расстоянии и хрупких связях, где слова прошлого всё ещё витают в воздухе, словно надежда на чудо.', 'https://image.tmdb.org/t/p/w500/nhvPn4TsUQk5ZBk9T9RBW7v7z1J.jpg', 5, '2026-07-15 14:32:35');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (243, 'Любит — не любит', 2014, 'Аниме', 3, 'Леша и Алена вот-вот должны пожениться. И все бы ничего, если бы не знакомство Леши с известной журналисткой Ирой накануне помолвки. Её образ никак не вписывается в рамки привычной для Алексея жизни. Ира вносит хаос в его жизнь, а Алёна — наивная девушка, любит его таким, какой он есть, и мечтает стать его женой.  Авантюризм Иры и ее готовность совершать безумные поступки дают Леше понять, что его жизнь может быть гораздо красочнее. Но готов ли он к авантюрным поступкам, когда на кону счастливое будущее с Аленой?', 'https://image.tmdb.org/t/p/w500/rNksTWnP6V3eJREywP6rRACmPyl.jpg', 5, '2026-07-15 14:32:35');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (244, 'Украсить цветами обещания прощальное утро', NULL, 'Аниме', NULL, NULL, NULL, 5, '2026-07-15 14:32:36');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (245, 'Связанные', 1988, 'Аниме', 4, 'Два тела. Два разума. Одна душа. Братья Мэнтл — абсолютно идентичные близнецы. Оба они врачи и работают вместе. Эллиот искусней Бева в деле соблазнения женщин и охотно «дарит» брату своих любовниц, которые и не подозревают о «подмене». Но когда их клинику посещает кинозвезда Клэр, застенчивый Бев влюбляется в нее первым. Клэр, сама того не ведая, начинает встречаться с обоими братьями. Смогут ли они «поделить» любимую женщину или, пытаясь найти утешение в наркотиках и алкоголе, погрузятся в пучину безумия?', 'https://image.tmdb.org/t/p/w500/iat5GeDbjBEINnqUNBl7NKiVa4A.jpg', 5, '2026-07-15 14:32:36');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (246, 'Наруто', NULL, 'Аниме', 4, 'В сериале «Наруто» рассказ ведётся о начинающих ниндзя, только-только окончивших академию и получивших «удостоверения» в виде повязок. Сразу же после окончания герои попадают во множество переделок и опасных ситуаций, находят друзей, встречают врагов.', 'https://image.tmdb.org/t/p/w500/ply5yM9ylDMy8t13pkqKmJlLsJP.jpg', 5, '2026-07-15 14:32:37');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (247, 'Боруто', NULL, 'Аниме', 4, 'Увлекательный и красочный мир шиноби после завершения аниме сериала "Наруто: Ураганные хроники" нас не покинул. Вот только главный герой Наруто теперь глава Конохи и в этом сериале речь пойдет уже не о нем, а о его сыне - Боруто.  Мир очень сильно изменился, он сделал большой прорыв в современность, но главная идея и традиции жителей не поменялись. Теперь отважному Боруто придется возложить на свои плечи все хлопоты своего отца и доказать всем, что он достоин называться сыном величайшего Наруто. Ему еще стоит изучить много новых боевых техник и сразиться с по-настоящему опасными соперниками.', 'https://image.tmdb.org/t/p/w500/hi8zozWxA2w8W5SNt5qiKpokXdK.jpg', 5, '2026-07-15 14:32:37');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (248, 'Седьмая жизнь злодейки: узы вражды', NULL, 'Аниме', NULL, NULL, NULL, 5, '2026-07-15 14:32:38');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (249, 'Повар небесной гостиницы', NULL, 'Аниме', 4, 'Главная героиня аниме по имени Аой не подозревала, что ее дедуля заключил сделку с демоном, а расплачиваться предстоит именно ей. Девушка оказалась во владения дьявола, где теперь выступает в роли жены ненасытного демона. Правда, главная героиня решает отдать долг деда не классическим супружеским методом, а работой в местном ресторанчике. За несколько лет труда здесь ей удастся накопить нужную сумму для откупа и вернуться в родной мир после продолжительного заточения. Главная героиня знакомится с местными жителями, среди которых находятся неплохие собеседники и весьма интересные личности.', 'https://image.tmdb.org/t/p/w500/82VaDgYOSA1Sk36vn5SQha9IgRJ.jpg', 5, '2026-07-15 14:32:38');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (250, 'Сказка о сахарном яблоке', NULL, 'Аниме', NULL, NULL, NULL, 5, '2026-07-15 14:32:38');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (251, 'Принесённая в жертву принцесса и царь зверей', NULL, 'Аниме', 3, 'Лет сто назад между людьми и зверолюдьми разразилась великая война, которая унесла множество невинных жизней и закончилась перемирием сторон. Одним из условий хрупкого равновесия стало ежегодное человеческое жертвоприношение Царю зверей. Вот уже век продолжается кровавый ритуал и уже девяносто восемь девушек было отдано на съедение, и теперь та же участь ждёт юную Салифи. Специально для этой цели пятнадцатилетнюю девочку забрали из родной деревни и вывезли в королевство Озмарго, куда вход людям запрещён.

Оптимистичная Салифи, которая полна веры в лучшее и совсем не боится зверолюдей, отличается от всех тех людей, с которыми приходилось сталкиваться Царю зверей Леонхарту. Он заинтригован личностью девушки и её прошлым, поэтому не только оставляет её в живых, но и позволяет свободно путешествовать по стране, несмотря на возможные протесты соплеменников. Только Салифи и Леонхарт ещё не осознают, что мгновения, проведённые вместе, уже отражаются на будущем королевства.', 'https://image.tmdb.org/t/p/w500/qmu5Ry16ZcqLyCZS8sWGEBxeGWT.jpg', 5, '2026-07-15 14:32:39');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (252, 'Холодное сердце (2025)', NULL, 'Фантастика', NULL, NULL, NULL, 5, '2026-07-15 14:33:36');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (253, 'Дети леса 2', NULL, 'Мультфильм', NULL, NULL, NULL, 5, '2026-07-15 14:33:37');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (254, 'Викинги', 2013, 'Драма', 4, 'Сериал рассказывает об отряде викингов Рагнара Лодброка. Он восстал, чтобы стать королём племён викингов. Норвежская легенда гласит, что он был прямым потомком Одина, бога войны и воинов.', 'https://image.tmdb.org/t/p/w500/1de3R902B5EEMmohBQsExd5V87Y.jpg', 3, '2026-07-15 14:38:59');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (255, 'Последнее королевство', 2015, 'Драма', 4, 'Сериал рассказывает о временах правления короля Уэссекса Альфреда Великого, сумевшего отвоевать английские земли у датских викингов — заморских захватчиков. Главным героем повествования выступает ещё в младенчестве похищенный данами Утред — потомок благородного саксонского рода. Воспитанный как викинг, в очень непростой момент жизненного выбора молодой воин должен будет решить для себя, чью сторону он примет в решающих сражениях за судьбу древней Британии.', 'https://image.tmdb.org/t/p/w500/eXRWYkffOq0be8hNlQTNeB0yLPX.jpg', 3, '2026-07-15 14:38:59');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (256, 'Мерлин', 2008, 'Фантастика', 4, 'Это история юного мага, ставшего впоследствии самым знаменитым и могущественным волшебником из всех, когда-либо живших на земле. Действие начинается с того дня, когда юный волшебник впервые оказывается в королевстве Камелот, и повествует о событиях, предшествующих легендарной истории о Мерлине и короле Артуре. Действующий король Камелота уже более двадцати лет ведет ярую войну против магии. Он запрещает гражданам своего королевства использовать ее в жизни, так как когда-то это перешло все границы дозволенного, каждый мог по книгам обучиться искусству колдовства и применять магию во зло, а не во благо.Чтобы навести порядок, король уничтожает практически всех драконов, изгоняет из королевства или приказывает публично казнить колдунов. И вот когда с магией и колдовством вроде бы покончено, король решает отпраздновать это большим пиром, на котором, именно с помощью волшебства, Мерлин спасет единственного и любимого сына короля - Артура. С этого момента судьбы Мерлина и Артура будут крепко связаны, и именно благодаря Мерлину, в будущем Артур станет королем Альбиона…', 'https://image.tmdb.org/t/p/w500/hlkMtAN7D8QQE5YEBy6Ta2aQhhq.jpg', 3, '2026-07-15 14:39:00');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (257, 'Сверхестественное', 2005, 'Ужасы', 4, 'Сериал рассказывает о приключениях братьев Сэма и Дина Винчестеров, которые путешествуют по Соединённым Штатам на чёрном автомобиле Chevrolet Impala 1967 года, расследуют паранормальные явления, многие из которых основаны на американских городских легендах и фольклоре, и сражаются с порождениями зла, такими как демоны и призраки.', 'https://image.tmdb.org/t/p/w500/hvO99pEfSBxF55clgs8r4mpRzr.jpg', 3, '2026-07-15 14:39:00');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (258, 'Ведьмак', 2019, 'Фантастика', 4, 'Геральт из Ривии, наемный охотник за чудовищами, перенесший мутации, идет навстречу своей судьбе в неспокойном мире, где люди часто оказываются куда коварнее чудовищ.', 'https://image.tmdb.org/t/p/w500/rY2c2LhN07CRKlAbRaDZxN2XjvK.jpg', 3, '2026-07-15 14:39:01');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (259, 'Сёгун', 2024, 'Исторический', 4, 'Япония, начало XVII века. Английский штурман Джон Блэкторн терпит крушение и попадает в закрытую для европейцев Страну восходящего солнца, где проходит путь от пленника на грани жизни и смерти до правой руки борющегося за власть самурая Торанаги.', 'https://image.tmdb.org/t/p/w500/cOKLRblbdBtcuf4TkAzsyJpZr23.jpg', 3, '2026-07-15 14:39:01');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (260, 'Падение ордена', NULL, 'Фантастика', NULL, NULL, 'https://image.tmdb.org/t/p/w500/rrRLdt3SL98y6FPKpfedBBvLOV8.jpg', 3, '2026-07-15 14:39:02');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (261, 'Локи', 2021, 'Фантастика', 4, 'После кражи Тессеракта во время событий фильма «Мстители: Финал» альтернативная версия Локи попадает в таинственное Управление временными изменениями, бюрократическую организацию, существующую вне времени и пространства и контролирующую стабильность «Священной линии времени» и единообразность течения времени. Они дают Локи выбор: быть стёртым из существования из-за того, что он является «вариантом», или помочь исправить временную линию и остановить более серьёзную угрозу.', 'https://image.tmdb.org/t/p/w500/fNTS8BOMmhYYM4FqLPLuJ6KRQEF.jpg', 3, '2026-07-15 14:39:02');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (262, 'Как закалялся стайл', 2022, 'Комедия', 3, 'В недалеком будущем Софи рассказывает своему сыну историю о том, как она познакомилась с его отцом. Эта история переносит нас в 2021 год, где Софи и ее сплоченная компания друзей находятся в процессе выяснения того, кто они, чего хотят от жизни и как влюбиться в эпоху приложений для знакомств и безграничных возможностей.', 'https://image.tmdb.org/t/p/w500/e6DPQEINVSreUAvmTF0MrZRIKsS.jpg', 3, '2026-07-15 14:39:03');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (263, 'Сеструха', 2024, 'Драма', 4, NULL, 'https://image.tmdb.org/t/p/w500/wrEpO761kdjBijJSn09uiN4fdjM.jpg', 3, '2026-07-15 14:39:04');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (264, 'Полицейский с рублёвки', 2016, 'Комедия', 4, '«Полицейский с Рублёвки» - это история о Грише Измайлове, полицейском, который призван охранять покой и порядок в самом элитном районе России, где живут невероятно богатые люди. Ему приходится расследовать дела, в которые впутываются жители Рублевки, и делает он это нередко превышая свои полномочия. Грише около 30 лет, он красив, одинок, богат, циничен, азартен и ко всему относится с изрядной долей черного юмора. Он заботится о младшей сестре-хулиганке, которую вынужден постоянно вытаскивать из неприятностей. Гриша не прикладывая усилий умеет нравиться женщинам и регулярно издевается над своим начальником Яковлевым.', 'https://image.tmdb.org/t/p/w500/3la60SBas5hWMP2C5mzb6WXL89S.jpg', 3, '2026-07-15 14:39:04');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (265, '911', 2018, 'Драма', 4, 'Сериал расскажет о работе полицейских, «Скорой помощи» и пожарной службы. Все они выполняют свой долг, часто рискуя жизнью и попадая в самые пугающие и шокирующие ситуации. Смысл их ежедневной работы состоит в охране безопасности улиц и помощи всем, кто в ней нуждается. Полицейские, пожарные и парамедики работают бок о бок в жестких условиях большого города. Эти экстренные службы должны стараться балансировать, спасая тех, кто находится в наиболее уязвимом положении, и при этом решать проблемы в их собственной жизни.', 'https://image.tmdb.org/t/p/w500/6njUqsd3By2mJsdZm1P0moPLzs3.jpg', 3, '2026-07-15 14:39:05');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (266, 'Новичок', 2018, 'Боевик', 4, 'Начинать с чистого листа всегда нелегко, особенно для уроженца маленького городка Джона Нолана, который после инцидента, перевернувшего его жизнь, решил воплотить в жизнь давнюю мечту и присоединиться к полиции Лос-Анджелеса. Возрастного новичка встречают с понятным скептицизмом, однако жизненный опыт, упорство и чувство юмора дают Джону преимущество.', 'https://image.tmdb.org/t/p/w500/jfxInWjSixQeeyT7oiBvdXjd7HM.jpg', 3, '2026-07-15 14:39:05');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (267, 'Декстер', 2006, 'Криминал', 4, 'Один из самых популярных криминальных сериалов – история судмедэксперта в полиции Майами, который по совместительству еще и серийный убийца. Ребенком ставший свидетелем жестокой расправы над своей матерью, Декстер Морган (Майкл С. Холл) был усыновлен добрым полицейским Гарри Морганом. Чуткий и опытный профессионал вовремя распознал социопатические наклонности мальчика и умело направил его непомерную жажду убийства в «правильное» русло. Выросший положительным героем, парень совершает убийства, руководствуясь своим собственным моральным кодексом. Он лишает жизни только тех, кто этого заслуживает, – большинство жертв Декстера избежавшие правосудия убийцы (если не считать некоторой погрешности и косвенно пострадавших).', 'https://image.tmdb.org/t/p/w500/93dEzWiupRP0Rq8S87MzfzSHS1x.jpg', 3, '2026-07-15 14:39:06');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (268, 'Доктор Кто', 2005, 'Фантастика', 4, 'Инопланетянин-гуманоид, называющий себя Доктором, путешествует через время и пространство в космическом корабле, который снаружи выглядит как полицейская будка 50-х годов. Доктор чрезвычайно эксцентричен и имеет невероятные знания в областях технологии, истории и науки. Он путешествует вместе со своими компаньонами, попутно борясь против космических злодеев и спасая Землю от бесчисленных врагов.', 'https://image.tmdb.org/t/p/w500/4yAIKCTUumob1Xx38yuW1U9IbJe.jpg', 3, '2026-07-15 14:39:06');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (269, 'Доктор Хаус', 2004, 'Драма', 4, 'Сериал рассказывает о команде врачей, которые должны правильно поставить диагноз пациенту и спасти его. Возглавляет команду доктор Грегори Хаус, который ходит с тростью после того, как его мышечный инфаркт в правой ноге слишком поздно правильно диагностировали. Как врач Хаус просто гений, но сам не отличается проникновенностью в общении с больными и с удовольствием избегает их, если только есть возможность. Он сам всё время проводит в борьбе с собственной болью, а трость в его руке только подчеркивает его жесткую, ядовитую манеру общения. Порой его поведение можно назвать почти бесчеловечным, и при этом он прекрасный врач, обладающий нетипичным умом и безупречным инстинктом, что снискало ему глубокое уважение. Будучи инфекционистом, он ещё и замечательный диагност, который любит разгадывать медицинские загадки, чтобы спасти кому-то жизнь. Если бы все было по его воле, то Хаус лечил бы больных не выходя из своего кабинета.', 'https://image.tmdb.org/t/p/w500/hXoGcvNOeWZkxbaitu7ZvEM0hQJ.jpg', 3, '2026-07-15 14:39:07');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (270, 'Мандалорец', 2019, 'Фантастика', 4, 'Угрюмый воин-мандалорец, никогда не снимающий шлем, работает наёмником и почти все сбережения отдаёт своим сородичам, которые, некогда будучи великой расой, теперь скрываются под землёй и тихо восстанавливают былую славу. На одном из особо дорогих заданий грозный бывший имперец поручает Мандалорцу доставить живым или мёртвым некое существо. Им оказывается маленькое милое существо, и герой — понимая, что ничего хорошего с этим Малышом делать клиент не собирается, — начинает нелёгкую борьбу с собственной совестью.', 'https://image.tmdb.org/t/p/w500/3JcJfU9wm6sA2R6LQtnsBJsHMmY.jpg', 3, '2026-07-15 14:39:07');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (271, 'Первый мститель', 2011, 'Боевик', 4, 'Стив Роджерс добровольно соглашается принять участие в эксперименте, который превратит его в суперсолдата, известного как Капитан Америка. Роджерс вступает в вооружённые силы США вместе с Баки Барнсом и Пегги Картер, чтобы бороться с враждебной организацией ГИДРА, которой управляет безжалостный Красный Череп.', 'https://image.tmdb.org/t/p/w500/slr5pTsDIJS9oCfBEBTCYNiq6xs.jpg', 3, '2026-07-15 14:39:08');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (272, 'Железный человек', 2008, 'Боевик', 4, 'Миллиардер изобретатель Тони Старк попадает в плен к Афганским террористам, которые пытаются заставить его создать оружие массового поражения. В тайне от своих захватчиков Старк конструирует высокотехнологичную киберброню, которая помогает ему сбежать. Однако по возвращению в США он узнаёт, что в совете директоров его фирмы плетётся заговор, чреватый страшными последствиями. Используя своё последнее изобретение, Старк пытается решить проблемы своей компании радикально…', 'https://image.tmdb.org/t/p/w500/wAKZudQn0HEXqLvaGN6BEripHbv.jpg', 3, '2026-07-15 14:39:08');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (273, 'Мстители', 2012, 'Фантастика', 4, 'В погоне за могуществом бог Локи вступает в сговор с воинственной расой Читаури, которая обещает ему армию для захвата Земли в обмен на Тессеракт – небольшой куб, содержащий в себе огромную силу. Проникнув в секретный центр организации «Щ.И.Т.», он объявляет о своих намерениях, после чего похищает Тессеракт и берет под контроль нескольких агентов, обеспечивших ему побег. В ответ на угрозу глава «Щ.И.Т.’а» Ник Фьюри созывает сильнейших супергероев планеты, которыми оказываются Железный человек, Черная вдова, Капитан Америка, Халк и Тор. Чтобы дать противнику достойный отпор, им придется отложить все свои разногласия и научиться работать в команде, иначе человечество ждет неминуемая гибель…', 'https://image.tmdb.org/t/p/w500/ztkYgL0zHJLnEPY5VabK9OlmXxx.jpg', 3, '2026-07-15 14:39:09');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (274, 'Стражи Галактики', 2014, 'Боевик', 4, 'Отважному путешественнику Питеру Квиллу попадает в руки таинственный артефакт, принадлежащий могущественному и безжалостному злодею Ронану, строящему коварные планы по захвату Вселенной. Питер оказывается в центре межгалактической охоты, где жертва — он сам. Единственный способ спасти свою жизнь — объединиться с четвёркой нелюдимых изгоев: воинственным енотом по кличке Ракета, человекоподобным деревом Грутом, смертельно опасной Гаморой и одержимым жаждой мести Драксом, также известным как Разрушитель. Когда Квилл понимает, какой силой обладает украденный артефакт и какую опасность он представляет для вселенной, одиночка пойдет на всё, чтобы сплотить случайных союзников для решающей битвы за судьбу галактики.', 'https://image.tmdb.org/t/p/w500/4uVdNj0FWCjtG1jEYASuNzE33LS.jpg', 3, '2026-07-15 14:39:09');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (275, 'Человек-муравей', 2015, 'Боевик', 4, 'Вооружившись удивительной способностью уменьшаться в размере, но обладать при этом большой силой, мошенник Скотт Лэнг должен стать героем и помочь своему наставнику, доктору Хэнку Пиму, сохранить в тайне существование костюма Человека-муравья от угроз нового поколения.', 'https://image.tmdb.org/t/p/w500/9cMJSp2LVSzmPzMWPHIHpeBfECr.jpg', 3, '2026-07-15 14:39:10');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (276, 'Человек-паук: Возвращение домой', 2017, 'Боевик', 4, 'Казалось бы, Питер Паркер всего лишь обычный школьник, живущий в Нью-Йорке, и занимающийся абсолютно тем же, что и его многочисленные сверстники. Но это только обман зрения, ведь на самом деле, он обладает особыми способностями после того, как его укусил радиоактивный паук. Следуя кредо его дяди Бэна «с великой силой приходит великая ответственность», Питер становится Человеком-пауком — героем, который пытается помогать людям. Но каково это быть героем в таком юном возрасте, особенно, когда ты находишься в мире, где существуют Мстители? Преследуемого подобными мыслями Человека-паука ждёт встреча с новым могущественным врагом, чьи действия могут уничтожить весь город.', 'https://image.tmdb.org/t/p/w500/gBCq5vt7XXUMjfxi2OguArduUKP.jpg', 3, '2026-07-15 14:39:10');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (277, 'Доктор Стрэндж', 2016, 'Фантастика', 4, 'Страшная автокатастрофа поставила крест на карьере успешного нейрохирурга Доктора Стрэнджа. Отчаявшись, он отправляется в путешествие в поисках исцеления и открывает в себе невероятные способности к трансформации пространства и времени. Теперь он — связующее звено между параллельными измерениями, а его миссия — защищать жителей Земли и противодействовать Злу, какое бы обличие оно ни принимало.', 'https://image.tmdb.org/t/p/w500/fR4oifDjoGFAyhWyPUl3h9H1xpQ.jpg', 3, '2026-07-15 14:39:11');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (278, 'Черная Пантера', 2018, 'Боевик', 4, 'С первого взгляда можно решить, что Ваканда — обычная территория дикой Африки, но это не так. Здесь, в недрах пустынных земель, скрываются залежи уникального металла, способного поглощать вибрацию. Многие пытались добраться до него, разоряя всё на своём пути и принося смерть аборигенам, но каждый раз таинственный дух саванны — Чёрная Пантера — вставал на защиту угнетённых.  Спустя много лет беда снова приходит в Ваканду, и в этот раз враг заручился поддержкой современных технологий. Когда шансов почти не остаётся, Т`Чалла, молодой принц Ваканды, узнаёт, что именно ему предстоит возродить легенду и продолжить вечную борьбу, надев маску Чёрной Пантеры.', 'https://image.tmdb.org/t/p/w500/ndpwgAANbZSMwgTcxmQ7o4SKDsd.jpg', 3, '2026-07-15 14:39:11');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (279, 'Человек-паук: Вдали от дома', 2019, 'Боевик', 4, 'Питер Паркер вместе с одноклассниками отправляется на летние каникулы в Европу. Однако отдохнуть приятелям вряд ли удастся — по прибытии в Венецию группа попадает в эпицентр сражения. Некое существо, состоящее из воды, появляется из ниоткуда и начинает крушить всё на своём пути, и теперь Питеру придётся спасать европейские архитектурные памятники вместе с загадочным супергероем Мистерио.', 'https://image.tmdb.org/t/p/w500/5OSCB19RavySNpaDGtPIuByDgoa.jpg', 3, '2026-07-15 14:39:12');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (280, 'Человек-паук: Нет пути домой', 2021, 'Боевик', 4, 'Жизнь и репутация Питера Паркера оказываются под угрозой, поскольку Мистерио раскрыл всему миру тайну личности Человека-паука. Пытаясь исправить ситуацию, Питер обращается за помощью к Стивену Стрэнджу, но вскоре всё становится намного опаснее.', 'https://image.tmdb.org/t/p/w500/qad0kyRLHG1Qccp2A0YCCUbvhiD.jpg', 3, '2026-07-15 14:39:12');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (281, 'Человек-паук 1', 2002, 'Боевик', 4, 'После укуса генетически изменённого паука, застенчивый школьник Питер Паркер обнаруживает у себя невероятные способности: сверхчеловеческую силу, ловкость и умение передвигаться по городу на паутине. Решив использовать свой дар во благо, он становится Человеком-пауком и начинает защищать жителей Нью-Йорка от преступности. Но настоящим испытанием для героя становится появление опасного Зелёного гоблина - могущественного противника, который угрожает всему городу и заставляет Питера сделать непростой выбор между личной жизнью и ответственностью, которую несут его новые способности.', 'https://image.tmdb.org/t/p/w500/uxNYgyfM9zeIQevvLON8zlPLocS.jpg', 3, '2026-07-15 14:39:13');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (282, 'Человек-паук 2', 2004, 'Боевик', 4, 'Питер пытается совмещать обычную жизнь, учёбу и обязанности Человека-паука, но постоянные жертвы начинают разрушать его отношения с близкими. Когда талантливый учёный Отто Октавиус превращается в опасного Доктора Осьминога, городу вновь требуется его защитник. Питеру предстоит сделать трудный выбор между личным счастьем и ответственностью, ведь иногда быть героем значит отказаться от того, чего хочешь больше всего.', 'https://image.tmdb.org/t/p/w500/VBS4TFi0R7nhrPeDAc6TmBt8XC.jpg', 3, '2026-07-15 14:39:13');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (283, 'Человек-паук 3', 2007, 'Боевик', 3, 'Питер наконец находит гармонию между жизнью супергероя и личным счастьем, но новые испытания снова меняют всё. Таинственная чёрная субстанция усиливает его способности, одновременно пробуждая тёмную сторону его характера. В это же время на его пути появляются сразу несколько опасных противников - Песочный человек, Новый Гоблин и Веном. Чтобы защитить близких и спасти город, Питеру предстоит справиться не только с врагами, но и с собственными внутренними демонами.', 'https://image.tmdb.org/t/p/w500/ngNCHBZgNdbGisLbi1hImGh2SHl.jpg', 3, '2026-07-15 14:39:14');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (284, 'Новый человек-паук', 2012, 'Боевик', 3, 'В детстве Питер Паркер был оставлен своими родителями, и поэтому воспитывался дядей и тётей. Шли годы, Питер был обычным примерным школьником, подвергался нападкам хулиганов и был влюблён в свою одноклассницу Гвен Стэйси, которая сама втайне отвечала ему взаимностью. Но после укуса генетически изменённого паука, Питер получает невероятные сверхспособности и его жизнь меняется навсегда.  Однако его не перестаёт мучить вопрос о том, что случилось с его родителями. Он знакомится с давним другом и партнёром своего отца — генетиком Куртом Коннорсом, который вместе с отцом Питера разрабатывал формулу регенерации. Питер помогает её закончить, а Коннорс, всю жизнь мечтавший восстановить свою правую руку, вводит формулу себе и становится Ящером. Осознавая свою вину, Питер начинает новую жизнь в образе таинственного супергероя Человека-паука и становится грозой преступников, одновременно пытаясь найти способ остановить Коннорса.', 'https://image.tmdb.org/t/p/w500/kby3x8wic9Lx4qEfstLu2vFHTVj.jpg', 3, '2026-07-15 14:39:15');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (285, 'Лунный рыцарь', 2019, 'Боевик', 3, NULL, 'https://image.tmdb.org/t/p/w500/zza4RNs6ZXRNJY3LvUy0MKPIW2x.jpg', 3, '2026-07-15 14:39:15');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (286, 'Тор: Любовь и гром', 2022, 'Боевик', 3, 'Джейн Фостер берет на себя обязанности Бога-громовержца и становится обладательницей молота Мьёльнира.', 'https://image.tmdb.org/t/p/w500/xWA0Av3mO7uH2bqGU7QMfckY9si.jpg', 3, '2026-07-15 14:39:16');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (287, 'Бэтмен (2022)', 2022, 'Боевик', 4, 'После двух лет поисков правосудия на улицах Готэма для своих сограждан Бэтмен становится олицетворением беспощадного возмездия. Когда в городе происходит серия жестоких нападений на представителей элиты, загадочные улики приводят Брюса Уэйна в самые темные закоулки преступного мира, где он встречает Женщину-Кошку, Пингвина, Кармайна Фальконе и Загадочника. Теперь под прицелом оказывается сам Бэтмен, которому предстоит отличить друга от врага и восстановить справедливость во имя Готэма.', 'https://image.tmdb.org/t/p/w500/3EXgl14Wmr5NcbYnBy1kavGHnvh.jpg', 3, '2026-07-15 14:39:16');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (288, 'Бэтмен против Супермена', 2016, 'Боевик', 3, 'Опасаясь, что действия богоподобного супергероя так и останутся бесконтрольными, грозный и могущественный страж Готэм Сити бросает вызов самому почитаемому в наши дни спасителю Метрополиса, в то время как весь остальной мир решает, какой герой ему по-настоящему нужен. И пока Бэтмен и Супермен пребывают в состоянии войны друг с другом, возникает новая угроза, которая ставит человечество под самую большую опасность, с которой оно когда-либо сталкивалось.', 'https://image.tmdb.org/t/p/w500/tAQOcxxcZbpM1jEhz7hJC5nmCDi.jpg', 3, '2026-07-15 14:39:17');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (289, 'Очень страшное кино', 1999, 'Комедия', 2, NULL, 'https://image.tmdb.org/t/p/w500/ib66R8D34o2Bffmp0dk5UUB6WHA.jpg', 3, '2026-07-15 14:39:17');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (290, 'Борат', 2006, 'Комедия', 3, 'Телеведущий из Казахстана Борат отправляется в США, чтобы сделать репортаж об этой «величайшей в мире стране». Однако по прибытии оказалось, что главная цель его визита — поиски Памелы Андерсон с целью жениться на ней, а вовсе не съёмки документального фильма…', 'https://image.tmdb.org/t/p/w500/bTUFtYSjjvmWTPa9oLzJK5qYVqn.jpg', 3, '2026-07-15 14:39:18');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (291, 'Зелёная миля', 1999, 'Драма', 4, 'Пол Эджкомб — начальник блока смертников в тюрьме «Холодная гора», каждый из узников которого однажды проходит «зеленую милю» по пути к месту казни. Пол повидал много заключённых и надзирателей за время работы. Однако гигант Джон Коффи, обвинённый в страшном преступлении, стал одним из самых необычных обитателей блока.', 'https://image.tmdb.org/t/p/w500/lHxe8t4B0CKv4DO0C0B4rsuiG95.jpg', 3, '2026-07-15 14:39:18');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (292, 'Зелёная книга', 2018, 'Комедия', 4, 'В 1962 году Тони Лип, вышибала, был нанят в качестве водителя для пианиста Дона Ширли, чтобы сопровождать его в турне по южным штатам — в те времена, когда афроамериканцы полагались на путеводитель под названием «Зелёная книга негритянского автомобилиста».', 'https://image.tmdb.org/t/p/w500/fYch3e75YFnsJS9wAOOMlzErMqR.jpg', 3, '2026-07-15 14:39:19');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (293, 'Кит', 2022, 'Драма', 4, 'Чарли зарабатывает на жизнь преподаванием английского языка онлайн, однако его беззаботные будни портит серьёзная проблема со здоровьем: он страдает от ожирения. Стесняясь своего внешнего вида, мужчина врёт ученикам о том, что его камера на ноутбуке сломана, никогда не покидает пределов квартиры и заказывает доставку еды. Единственным человеком, который время от времени навещает его, оказывается близкая подруга и медсестра Лиз. Когда Чарли узнаёт о том, что его кровяное давление подобралось к потенциально опасным для жизни значениям, он отказывается проходить курс лечения, решив посвятить свободное время общению со своей талантливой, отчуждённой и глубоко обеспокоенной дочерью Элли.', 'https://image.tmdb.org/t/p/w500/bUA6X03vffX3qCy3diF91PFo428.jpg', 3, '2026-07-15 14:39:19');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (294, 'Не грози Южному централу', 1996, 'Комедия', 4, 'Молодой афроамериканец по прозвищу Пепельница переезжает в Лос-Анджелес со своим отцом и бабушкой. Пепельница гордится тем, что они с отцом выглядят ровесниками, это, по его мнению, «очень круто». Гордится он и своей бабушкой, которая в свои-то преклонные годы покуривает и не стесняется крепких словечек. Вскоре Пепельница знакомится со своим кузеном по прозвищу Цепной Пес. Этот парень — гангстер, в его личном арсенале не только пистолеты и автомат, но и термоядерная боеголовка — «для самозащиты». Пепельница должен выбрать свой дальнейший путь в жизни: он может быть «просто хорошим чернокожим» или стать «опасным чернокожим», примкнув к банде своего кузена.', 'https://image.tmdb.org/t/p/w500/kVxJ6XaAk9koceTmmw8aSEwwHSj.jpg', 3, '2026-07-15 14:39:20');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (295, 'Побег из Шоушенка', 1994, 'Драма', 4, 'Бухгалтер Энди Дюфрейн обвинён в убийстве собственной жены и её любовника. Оказавшись в тюрьме под названием Шоушенк, он сталкивается с жестокостью и беззаконием, царящими по обе стороны решётки. Каждый, кто попадает в эти стены, становится их рабом до конца жизни. Но Энди, обладающий живым умом и доброй душой, находит подход как к заключённым, так и к охранникам, добиваясь их особого к себе расположения.', 'https://image.tmdb.org/t/p/w500/yvmKPlTIi0xdcFQIFcQKQJcI63W.jpg', 3, '2026-07-15 14:39:20');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (296, 'Титаник', 1997, 'Мелодрама', 4, 'В 1996-ом году команда охотника за сокровищами Брока Лаветта исследует морское дно в месте затопления легендарного «Титаника», надеясь обнаружить драгоценное ожерелье с редким бриллиантом, предположительно погребённое вместе с судном. Во время погружения сотрудникам Брока удаётся поднять старинный сейф, в котором они находят прекрасно сохранившийся рисунок девушки с ожерельем на шее. Женщиной, запечатлённой на рисунке, оказывается ныне 101-летняя Роуз Бьюкейтер, которая впоследствии соглашается поведать о своём путешествии на «Титанике». Её история начинается в 1912-ом году, когда 17-летняя Роуз, путешествующая с надменной матерью и богатым женихом, встречает бедняка Джека Доусона, выигравшего билет на корабль в карты.', 'https://image.tmdb.org/t/p/w500/r3sYKBtoNHPyS9vkaA8dJyh8grG.jpg', 3, '2026-07-15 14:39:21');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (297, 'Хатико', 2009, 'Драма', 4, 'В основе сюжета — реальная история, случившаяся в Японии в 20-х годах и потрясшая весь мир. Однажды, возвращаясь с работы, профессор колледжа нашел на вокзале симпатичного щенка породы акита-ину. Профессор и Хатико стали верными друзьями. Каждый день пес провожал и встречал профессора на вокзале. И даже потеря хозяина не остановила пса в его надежде, что друг вернется. После смерти Хатико и в силу широкого резонанса, который получила эта история, на станции Шибуя в Токио, на том месте, где он в течение 9 лет каждый день в 5 часов вечера приходил и ждал хозяина, было решено воздвигнуть бронзовый памятник в 1934г. в его честь. Сегодня памятник Хатико это – дань уважения преданности и верности, которой характеризуется эта порода.', 'https://image.tmdb.org/t/p/w500/gYfdHi4GvfEn1ksGpRX1YryihD4.jpg', 3, '2026-07-15 14:39:21');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (298, 'Волк с Уолл-стрит', 2013, 'Комедия', 4, '1987 год. Джордан Белфорт становится брокером в успешном инвестиционном банке. Вскоре банк закрывается после внезапного обвала индекса Доу-Джонса. По совету жены Терезы Джордан устраивается в небольшое заведение, занимающееся мелкими акциями. Его настойчивый стиль общения с клиентами и врождённая харизма быстро даёт свои плоды. Он знакомится с соседом по дому Донни, торговцем, который сразу находит общий язык с Джорданом и решает открыть с ним собственную фирму. В качестве сотрудников они нанимают нескольких друзей Белфорта, его отца Макса и называют компанию «Стрэттон Оукмонт». В свободное от работы время Джордан прожигает жизнь: лавирует от одной вечеринки к другой, вступает в сексуальные отношения с проститутками, употребляет множество наркотических препаратов, в том числе кокаин и кваалюд. Однажды наступает момент, когда быстрым обогащением Белфорта начинает интересоваться агент ФБР...', 'https://image.tmdb.org/t/p/w500/ihlWMaVZVXFzxU5wwZnbHJZ7Zpx.jpg', 3, '2026-07-15 14:39:22');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (299, 'Однажды в Голливуде', 2019, 'Комедия', 4, 'В прошлом актер вестернов и его дублер стараются достичь славы в Голливуде. Их поиски успеха происходят на фоне печальных событий, связанных с небезызвестным Чарльзом Мэнсоном.', 'https://image.tmdb.org/t/p/w500/muqDW2S3rkZKAVLv4TE47IYg3O6.jpg', 3, '2026-07-15 14:39:22');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (300, 'Суперперцы', 2007, 'Комедия', 4, 'Сквозь огонь и водку трое приятелей спешат на вечеринку года в честь прощания с девственностью. Как взять на абордаж красотку-одноклассницу, подорвать полицейскую машину и остаться в живых?', 'https://image.tmdb.org/t/p/w500/2jc4Q1ToEsTSoqQNhCzbI0m1uaP.jpg', 3, '2026-07-15 14:39:23');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (301, 'Тупой и ещё тупее', 1994, 'Комедия', 3, 'Два полных придурка, Ллойд Крисмас и Харри Данн пытаются нагнать красивую девушку Мэри Суонсон, чтобы вручить ей потерянный ею чемоданчик-дипломат. Кретинам невдомек, что Мэри обронила его специально, в качестве выкупа по договоренности с бандитами, похитившими ее мужа. Ведь внутри лежит кругленькая сумма. На мохнатой машине уникальной марки «Овчарка» двое идиотов пересекают Америку от Род-Айленда до Колорадо, где и находят обворожительную Мэри, в которую Ллойд уже успел втюриться без памяти.', 'https://image.tmdb.org/t/p/w500/ciLqMDkjL2wJFXo07mmVC3TfnhJ.jpg', 3, '2026-07-15 14:39:23');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (302, 'Укрощение строптивого', 1999, 'Мелодрама', 4, 'Строгий отец поставил условие: Бьянка пойдет на свидание, если ее сестра Кэт тоже согласится встретиться с парнем. Но Кэт — синий чулок и отчаянная мужененавистница. Бьянка пытается найти для сестры такого же зануду, как она.', 'https://image.tmdb.org/t/p/w500/xR6j2HVYZEqQ1nKdSJVYNLAIIcN.jpg', 3, '2026-07-15 14:39:24');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (303, 'Блеф', NULL, 'Триллер', NULL, NULL, NULL, 3, '2026-07-15 14:39:25');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (304, 'Безумно влюблённый', 1992, 'Комедия', 2, NULL, 'https://image.tmdb.org/t/p/w500/yPkiX0PTJbGzbXI0l3O9cmP696G.jpg', 3, '2026-07-15 14:39:25');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (305, 'Однажды в Вегосе', 2008, 'Комедия', 3, 'После ночи кутежа в Городе Грехов двое совершенно незнакомых людей просыпаются в одной постели и пытаются восстановить ход событий вечера. Оказывается, они поженились и взяли огромный джек-пот. И вот на свежую голову молодожены (каждый сам про себя) разрабатывают план, как отделаться от своей «второй половины» и получить весь куш. Там, где замешаны деньги, нет места любви. Хотя в Вегасе случается всякое…', 'https://image.tmdb.org/t/p/w500/wu9qZz4D3xlSUGWJ5BrEgi99QBh.jpg', 3, '2026-07-15 14:39:26');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (306, 'Властелин колец', 2001, 'Фантастика', 4, 'Сказания о Средиземье — это хроника Великой войны за Кольцо, длившейся не одну тысячу лет. Тот, кто владел Кольцом, получал неограниченную власть, но был обязан служить злу. Тихая деревня, где живут хоббиты. Придя на 111-й день рождения к своему старому другу Бильбо Бэггинсу, волшебник Гэндальф начинает вести разговор о кольце, которое Бильбо нашел много лет назад. Это кольцо принадлежало когда-то темному властителю Средиземья Саурону, и оно дает большую власть своему обладателю. Теперь Саурон хочет вернуть себе власть над Средиземьем. Бильбо отдает Кольцо племяннику Фродо, чтобы тот отнёс его к Роковой Горе и уничтожил.', 'https://image.tmdb.org/t/p/w500/5CrZYYasUUxo71m0JXxTTDTsSpV.jpg', 5, '2026-07-15 14:39:26');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (307, 'Звёздные войны', 1977, 'Фантастика', 4, 'Татуин. Планета-пустыня. Уже постаревший рыцарь Джедай Оби Ван Кеноби спасает молодого Люка Скайуокера, когда тот пытается отыскать пропавшего дроида. С этого момента Люк осознает свое истинное назначение: он один из рыцарей Джедай. В то время как гражданская война охватила галактику, а войска повстанцев ведут бои против сил злого Императора, к Люку и Оби Вану присоединяется отчаянный пилот-наемник Хан Соло, и в сопровождении двух дроидов, R2D2 и C-3PO, этот необычный отряд отправляется на поиски предводителя повстанцев — принцессы Леи.', 'https://image.tmdb.org/t/p/w500/dgVxw0IN5qul6MSofHhDac74aoX.jpg', 3, '2026-07-15 14:39:27');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (308, 'Изгой Один', 2016, 'Фантастика', 4, 'Фильм рассказывает о событиях, которые предшествовали четвёртому эпизоду «Звёздных Войн». Узнав о том, что Империя построила самую совершенную боевую станцию, способную уничтожать целые планеты, Альянс Повстанцев собирает особый отряд под руководством бывшей преступницы Джин Эрсо, целью которого является чертежи совершенного оружия Империи.  Несмотря на то, что миссия кажется самоубийственной, отряд готов рискнуть всем ради победы. Однако расстановка сил резко меняется, когда Император посылает за ними своего самого страшного и могущественного приспешника — Дарта Вейдера, чьё присутствие гарантирует как минимум одно — отряду повстанцев не суждено вернуться со своей миссии живыми.', 'https://image.tmdb.org/t/p/w500/agKGn83Y380RKlakyVEIpTuMoA1.jpg', 3, '2026-07-15 14:39:27');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (309, 'Хан Соло', 2018, 'Фантастика', 3, 'Фильм расскажет о похождениях юного космического сорвиголовы Хана Соло и его верного напарника Чубакки и о том, как они стали самыми быстрыми пилотами и самыми хитрыми контрабандистами далёкой Галактики.', 'https://image.tmdb.org/t/p/w500/syDObMIKfE6MI5w9DAlofSr0QQl.jpg', 3, '2026-07-15 14:39:28');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (310, 'Гарри Поттер и философский камень', 2001, 'Приключения', 4, 'Жизнь десятилетнего Гарри Поттера нельзя назвать сладкой: родители умерли, едва ему исполнился год, а от дяди и тёти, взявших сироту на воспитание, достаются лишь тычки да подзатыльники. Но в одиннадцатый день рождения Гарри всё меняется. Странный гость, неожиданно появившийся на пороге, приносит письмо, из которого мальчик узнаёт, что на самом деле он - волшебник и зачислен в школу магии под названием Хогвартс. А уже через пару недель Гарри будет мчаться в поезде Хогвартс-экспресс навстречу новой жизни, где его ждут невероятные приключения, верные друзья и самое главное — ключ к разгадке тайны смерти его родителей.', 'https://image.tmdb.org/t/p/w500/q3LZNzwW7ZWu4kSFIPGcB5CYFE4.jpg', 5, '2026-07-15 14:53:12');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (311, 'Гарри Поттер и Тайная комната', 2002, 'Приключения', 4, 'Гарри Поттер переходит на второй курс Школы чародейства и волшебства Хогвартс. Эльф Добби предупреждает Гарри об опасности, которая поджидает его там, и просит больше не возвращаться в школу. Юный волшебник не следует совету эльфа и становится свидетелем таинственных событий, разворачивающихся в Хогвартсе. Вскоре Гарри и его друзья узнают о существовании Тайной Комнаты и сталкиваются с новыми приключениями, пытаясь победить темные силы.', 'https://image.tmdb.org/t/p/w500/33Wj3LSyoAqtqkeh7YXcVMvTQzc.jpg', 5, '2026-07-15 14:53:12');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (312, 'Гарри Поттер и узник Азкабана', 2004, 'Приключения', 4, 'Гарри, Рон и Гермиона возвращаются на третий курс школы чародейства и волшебства Хогвартс. На этот раз они должны раскрыть тайну узника, сбежавшего из тюрьмы Азкабан, чье пребывание на воле создает для Гарри смертельную опасность.', 'https://image.tmdb.org/t/p/w500/mncDize7FLO9RBovXKZ7LefUkbu.jpg', 5, '2026-07-15 14:53:13');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (313, 'Гарри Поттер и Кубок огня', 2005, 'Приключения', 4, 'Гарри Поттер, Рон и Гермиона возвращаются на четвёртый курс школы чародейства и волшебства «Хогвартс». При таинственных обстоятельствах Гарри отобран в число участников опасного соревнования — Турнира Трёх Волшебников, однако проблема в том, что все его соперники — намного старше и сильнее. К тому же, знаки указывают на возвращение Лорда Волдеморта. Вскоре Гарри предстоит побороться не только за победу в соревновании, но и, прежде всего, за свою жизнь...', 'https://image.tmdb.org/t/p/w500/wWlSRexsjrdTWBYY84s671dYde5.jpg', 5, '2026-07-15 14:53:13');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (314, 'Гарри Поттер и Орден Феникса', 2007, 'Приключения', 4, 'Гарри проводит свой пятый год в школе Хогвартс и обнаруживает, что многие из членов волшебного сообщества отрицают факт недавнего состязания юного волшебника с воплощением вселенского зла Волдемортом. Все делают вид, что не имеют ни малейшего представления, что злодей вернулся. Однако впереди волшебников ждет необычная схватка.', 'https://image.tmdb.org/t/p/w500/AvftUghR5CZT1VCYbWATs01Et1M.jpg', 5, '2026-07-15 14:53:14');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (315, 'Гарри Поттер и Принц-полукровка', 2009, 'Приключения', 4, 'Теперь не только мир волшебников, но и мир маглов ощущает на себе всевозрастающую силу Волан-де-Морта, а Хогвартс уже никак не назовешь надежным убежищем. Гарри подозревает, что в самом замке затаилась некая опасность, но Дамблдор больше сосредоточен на том, чтобы подготовить его к финальной схватке, которая, как он знает, уже не за горами. Вместе они пытаются разгадать секрет бессмертия Волан-де-Морта, а для этого Дамблдор приглашает на должность преподавателя по зельеварению своего старинного друга и коллегу — профессора Горация Слизнорта.', 'https://image.tmdb.org/t/p/w500/zhMOIXezutmTCeP1AvPZHakGCYs.jpg', 5, '2026-07-15 14:53:14');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (316, 'Гарри Поттер и Дары Смерти. Часть 1', 2010, 'Приключения', 4, 'Гарри Поттера ждёт самое страшное испытание в жизни — смертельная схватка с Волан-де-Мортом. Друзья и враги Гарри предстают в совершенно неожиданном свете. Граница между добром и злом становится всё призрачнее.', 'https://image.tmdb.org/t/p/w500/2M6jaFgspjqGNLW7nrpaItRTBst.jpg', 5, '2026-07-15 14:53:15');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (317, 'Гарри Поттер и Дары Смерти. Часть 2', 2010, 'Приключения', 4, 'Гарри Поттера ждёт самое страшное испытание в жизни — смертельная схватка с Волан-де-Мортом. Друзья и враги Гарри предстают в совершенно неожиданном свете. Граница между добром и злом становится всё призрачнее.', 'https://image.tmdb.org/t/p/w500/2M6jaFgspjqGNLW7nrpaItRTBst.jpg', 5, '2026-07-15 14:53:15');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (318, 'Голодные игры', 2012, 'Фантастика', 4, 'Будущее. Деспотичное государство ежегодно устраивает показательные игры на выживание, за которыми в прямом эфире следит весь мир. Жребий участвовать в Играх выпадает юной Китнисс и тайно влюбленному в нее Питу. Они знакомы с детства, но теперь должны стать врагами. Ведь по нерушимому закону Голодных игр победить может только один из 24 участников. Судьям не важно кто выиграет, главное — зрелище. И на этот раз зрелище будет незабываемым.', 'https://image.tmdb.org/t/p/w500/7j6qQ5CVxHRpEbWQpAPxk5EjB3v.jpg', 5, '2026-07-15 14:53:16');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (319, 'Голодные игры: И вспыхнет пламя', 2013, 'Приключения', 4, 'Сумев выжить на безжалостных Голодных играх, Китнисс Эвердин и Пит Мелларк тщетно пытаются забыть о том, что произошло с ними в Капитолии. Но президент Сноу, диктатор государства Панем, и его клика не готовы оставить девушку и парня в покое, считая их опасными.  Власти решают устроить показательные Игры, в которых примут участие победители прошлых лет от каждого дистрикта. Жребий брошен: Китнисс и Пит вынуждены вернуться на Арену. Вновь они лицом к лицу со смертью — ради своих близких, ради своего будущего, ради своей любви!', 'https://image.tmdb.org/t/p/w500/lKe3uEQKyc6uTAOlFt9KmxHs5eH.jpg', 5, '2026-07-15 14:53:16');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (320, 'Голодные игры: Сойка-пересмешница. Часть 1', 2014, 'Фантастика', 3, 'Таинственный Тринадцатый дистрикт выходит из тени, в которой скрывался долгие годы. Начинается война. Война за справедливость? Война за лучшее будущее? Возможно.  Китнисс в этой войне — символ сопротивления. И если она хочет не оказаться пешкой в чужой большой игре, если хочет, чтобы жизнь её любимого не принесли в жертву чужим интересам, ей придется стать сильной. Сильнее, чем на арене Голодных игр…', 'https://image.tmdb.org/t/p/w500/kPbFeomPFnnktdwBgCBZ24NhkTj.jpg', 5, '2026-07-15 14:53:17');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (321, 'Голодные игры: Сойка-пересмешница. Часть 2', 2015, 'Боевик', 3, 'Китнисс Эвердин и своенравный Пит Мелларк пытаются выиграть гражданскую войну между самодержавным Капитолием и истерзанными войной районами Панема…', 'https://image.tmdb.org/t/p/w500/iQSeemlBax66PWmUWjuKFVBLBBa.jpg', 5, '2026-07-15 14:53:17');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (322, 'Хроники Нарнии: Лев, колдунья и платяной шкаф', 2005, 'Приключения', 4, 'Когда Лондон начинает подвергаться бомбардировкам со стороны немецких военно-воздушных сил, четверых детей отправляют в деревню к старому другу семьи. В его доме дети обнаруживают таинственный шкаф, посредством которого они попадают в сказочную страну Нарнию, где обитают фантастические люди, животные и существа. Оказывается, что эта мирная страна находится под властью злой Колдуньи, из-за которой там вечная зима. Дети должны помочь царю Аслану победить Колдунью, разрушить заклинания и освободить жителей Нарнии...', 'https://image.tmdb.org/t/p/w500/2XVYzz5n5UzAKfkvekP72SgpJ3B.jpg', 5, '2026-07-15 14:53:18');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (323, 'Хроники Нарнии: Принц Каспиан', 2008, 'Приключения', 3, 'Люси, Сьюзен, Эдмунд и Питер возвращаются в Нарнию. В Англии прошло совсем немного времени, а в Нарнии - века. Страна находится под гнётом зловещего короля Мираза. Но у волшебного королевства есть одна надежда - юный принц Каспиан. Чтобы помочь Каспиану отвоевать трон, четверо героев собирают армию мифических существ во главе с Асланом...', 'https://image.tmdb.org/t/p/w500/n43CryBQ330tXklFURAjh7iwtn1.jpg', 5, '2026-07-15 14:53:19');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (324, 'Хроники Нарнии: Покоритель Зари', 2010, 'Приключения', 3, 'Эдмунд, Люси, их кузен Юстас и король Каспиан отплывают на корабле «Покоритель Зари» на поиски друзей отца Каспиана - семи лордов: Ревелиана, Берна, Аргоза, Мавроморна, Октезиана, Рестимара и Рупа, изгнанных во время недолгого правления тирана Мираза...', 'https://image.tmdb.org/t/p/w500/u3dV7HsWEEYNcjZVJ4JJdhBLsSE.jpg', 5, '2026-07-15 14:53:19');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (325, 'Сумерки', 2008, 'Фантастика', 3, 'Семнадцатилетняя девушка Белла переезжает к отцу в небольшой городок Форкс. Она влюбляется в загадочного одноклассника, который, как оказалось, происходит из семьи вампиров, отказавшихся от нападений на людей. Влюбиться в вампира. Это страшно? Это романтично, это прекрасно и мучительно, но это не может кончиться добром, особенно в вечном противостоянии вампирских кланов, где малейшее отличие от окружающих уже превращает вас во врага.', 'https://image.tmdb.org/t/p/w500/pWI6GBi4eMQttMtKSWbxIFO2HqC.jpg', 5, '2026-07-15 14:53:20');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (326, 'Сумерки. Сага. Новолуние', 2009, 'Приключения', 3, 'Влюбиться в вампира — страшно и романтично. Но потерять любимого, решившего ценой разрыва спасти свою девушку от роли пешки в вечном противостоянии кланов «ночных охотников», — это просто невыносимо. Белла Свон мучительно переживает исчезновение Эдварда и безуспешно ищет забвения в дружбе с мальчишкой-индейцем Джейкобом Блэком. Она даже не подозревает, что её лучший друг — порождение ещё одного «народа Тьмы». Народа, куда более жестокого и опасного, чем аристократы-вампиры...', 'https://image.tmdb.org/t/p/w500/skucxWub4EZh1spfrgVFOlHwYCU.jpg', 5, '2026-07-15 14:53:20');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (327, 'Сумерки. Сага. Затмение', 2010, 'Приключения', 3, 'Сиэтл охвачен чередой таинственных убийств, а обуреваемая жаждой мести вампирша продолжает поиски Беллы, снова оказавшейся в смертельной опасности. Кроме того, находясь в эпицентре всех событий, Белла вынуждена делать выбор между любовью к Эдварду и дружбой с Джейкобом, зная что ее решение может послужить толчком к возобновлению давнего противостояния между вампирами и оборотнями. Помимо всего прочего, ей предстоит принять еще одно важное решение: жизнь или смерть, ведь окончание средней школы уже не за горами.', 'https://image.tmdb.org/t/p/w500/haWqUl5spYplB08e25VrIOSMNW.jpg', 5, '2026-07-15 14:53:21');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (328, 'Сумерки. Сага. Рассвет — Часть 1', 2011, 'Приключения', 3, 'В четвёртой части Белла Свон оказывается перед непростым выбором — сохранить жизнь себе или своему ребёнку (наполовину вампиру, наполовину человеку). Она решает оставить малыша, но Эдвард и остальные члены семьи Каллен категорически против. Помощи Бёлле ждать не от кого, но она приходит неожиданно, от того, от кого её совсем не ждали. Вдвоём Белла и Розали пытаются сохранить жизнь малышу, даже не догадываясь, к каким ужасающим последствиям это приведёт.', 'https://image.tmdb.org/t/p/w500/hnJ5U57LWu6xHp8w0z3o0ZdgFTf.jpg', 5, '2026-07-15 14:53:21');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (329, 'Сумерки. Сага. Рассвет — Часть 2', 2012, 'Фантастика', 3, 'Белла, став вампиром, постепенно свыкается со своей новой природой. В этом ей помогают Эдвард и остальные члены семьи Калленов. К тому же теперь у Беллы есть дочь Ренесми и вечность впереди. Джейкоб, запечатлённый с Ренесми, становится для девочки другом и наставником. Ненадолго для героев наступают спокойные, счастливые дни. Всё заканчивается, когда вести о Ренесми доходят до Вольтури. «Обращение» детей строго запрещено в мире вампиров. Не зная о необычном происхождении Ренесми, Вольтури собирают армию и направляются в Форкс, чтобы уничтожить Калленов.', 'https://image.tmdb.org/t/p/w500/fgVXAUj9w6OrVlhQ0YPiZhO46j5.jpg', 5, '2026-07-15 14:53:22');
INSERT INTO "movies" ("id", "title", "year", "genre", "rating", "description", "poster", "added_by", "created_at") VALUES (330, 'Царевна-лягушка 2', NULL, 'Мультфильм', NULL, NULL, NULL, 5, '2026-07-15 14:53:22');

DROP TABLE IF EXISTS "notifications";
CREATE TABLE notifications (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        user_id INTEGER NOT NULL REFERENCES users(id) ON DELETE CASCADE,
        title TEXT NOT NULL,
        body TEXT,
        type TEXT NOT NULL DEFAULT 'info',
        read INTEGER NOT NULL DEFAULT 0,
        created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
    );

DROP TABLE IF EXISTS "permissions";
CREATE TABLE permissions (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        code TEXT NOT NULL UNIQUE,
        module TEXT NOT NULL,
        description TEXT
    );

INSERT INTO "permissions" ("id", "code", "module", "description") VALUES (1, 'users.view', 'users', 'Просмотр пользователей');
